import {
  addDays,
  addMinutes,
  addMonths,
  addWeeks,
  addYears,
  eachDayOfInterval,
  endOfDay,
  endOfMonth,
  endOfWeek,
  getDay,
  isSameDay,
  isSameMonth,
  isSameYear,
  set,
  startOfDay,
  startOfMonth,
  startOfWeek,
} from "date-fns"

import { cn } from "@/lib/utils"

import type {
  CalendarBlockedRange,
  CalendarBusinessHoursWindow,
  CalendarClassNames,
  CalendarCreateOperation,
  CalendarEvent,
  CalendarMoveOperation,
  CalendarOccurrence,
  CalendarResizeOperation,
  CalendarSlot,
  CalendarView,
  CalendarWeekday,
} from "./types"
import { calendarViews } from "./types"

const MINUTES_IN_DAY = 1_440
const MILLISECONDS_IN_DAY = 86_400_000
const RECURRENCE_LIMIT = 400

const fallbackEventColors = [
  "#0f766e",
  "#2563eb",
  "#db2777",
  "#7c3aed",
  "#ea580c",
  "#059669",
] as const

type VisibleRangeOptions = {
  agendaDays?: number
  hiddenDays?: CalendarWeekday[]
  hourCycle?: 12 | 24
  locale?: string
  timeZone?: string
  weekStartsOn?: CalendarWeekday
}

type RecurrenceCursorContext = {
  rangeStart: Date
  rangeEnd: Date
}

type CalendarVisibleRange = {
  start: Date
  end: Date
}

type DayEventLayout = {
  occurrence: CalendarOccurrence
  column: number
  columns: number
  top: number
  height: number
}

type CalendarDateTimeFormatOptions = {
  hourCycle?: 12 | 24
  locale?: string
  timeZone?: string
}

type MinuteSegment = {
  endMinute: number
  startMinute: number
}

type DayTimeSegment = MinuteSegment & {
  color?: string
  id?: string
  label?: string
}

const allWeekdays: CalendarWeekday[] = [0, 1, 2, 3, 4, 5, 6]

export function getCalendarSlotClassName(
  classNames: CalendarClassNames | undefined,
  slot: CalendarSlot,
  ...values: Array<string | undefined>
) {
  return cn(values, classNames?.[slot])
}

export function normalizeHiddenDays(hiddenDays?: CalendarWeekday[]) {
  const nextHiddenDays = Array.from(new Set(hiddenDays ?? [])).filter(
    (day): day is CalendarWeekday => allWeekdays.includes(day as CalendarWeekday)
  )

  return nextHiddenDays.length === allWeekdays.length ? [] : nextHiddenDays
}

export function normalizeAvailableViews(availableViews?: CalendarView[]) {
  const nextAvailableViews = calendarViews.filter((view) =>
    availableViews?.includes(view)
  )

  return nextAvailableViews.length ? nextAvailableViews : [...calendarViews]
}

export function resolveCalendarView(
  view: CalendarView,
  availableViews?: CalendarView[]
) {
  const nextAvailableViews = normalizeAvailableViews(availableViews)

  return nextAvailableViews.includes(view) ? view : nextAvailableViews[0]
}

export function getNextVisibleDay(
  anchorDate: Date,
  hiddenDays?: CalendarWeekday[],
  direction: -1 | 1 = 1,
  includeAnchor = true
) {
  const nextHiddenDays = normalizeHiddenDays(hiddenDays)

  if (nextHiddenDays.length === 0) {
    return anchorDate
  }

  let cursor = anchorDate
  let stepsRemaining = 8

  if (!includeAnchor) {
    cursor = addDays(cursor, direction)
  }

  while (stepsRemaining > 0) {
    if (!nextHiddenDays.includes(getDay(cursor) as CalendarWeekday)) {
      return cursor
    }

    cursor = addDays(cursor, direction)
    stepsRemaining -= 1
  }

  return anchorDate
}

export function isHiddenDay(day: Date, hiddenDays?: CalendarWeekday[]) {
  return normalizeHiddenDays(hiddenDays).includes(getDay(day) as CalendarWeekday)
}

function getVisibleDaysInRange(
  range: CalendarVisibleRange,
  hiddenDays?: CalendarWeekday[]
) {
  return eachDayOfInterval(range).filter((day) => !isHiddenDay(day, hiddenDays))
}

export function parseTimeStringToMinuteOfDay(value: string) {
  const match = /^([01]?\d|2[0-3]):([0-5]\d)$/.exec(value.trim())

  if (!match) {
    return null
  }

  return Number(match[1]) * 60 + Number(match[2])
}

export function getVisibleRange(
  anchorDate: Date,
  view: CalendarView,
  options: VisibleRangeOptions = {}
): CalendarVisibleRange {
  const weekStartsOn = options.weekStartsOn ?? 1

  if (view === "month") {
    const monthStart = startOfMonth(anchorDate)
    const monthEnd = endOfMonth(anchorDate)

    return {
      start: startOfWeek(monthStart, { weekStartsOn }),
      end: endOfWeek(monthEnd, { weekStartsOn }),
    }
  }

  if (view === "week") {
    return {
      start: startOfWeek(anchorDate, { weekStartsOn }),
      end: endOfWeek(anchorDate, { weekStartsOn }),
    }
  }

  if (view === "agenda") {
    const agendaDays = options.agendaDays ?? 14

    return {
      start: startOfDay(anchorDate),
      end: endOfDay(addDays(anchorDate, agendaDays - 1)),
    }
  }

  return {
    start: startOfDay(anchorDate),
    end: endOfDay(anchorDate),
  }
}

export function shiftDate(
  anchorDate: Date,
  view: CalendarView,
  direction: -1 | 1,
  hiddenDays?: CalendarWeekday[]
) {
  if (view === "month") {
    return addMonths(anchorDate, direction)
  }

  if (view === "week" || view === "agenda") {
    return addWeeks(anchorDate, direction)
  }

  return getNextVisibleDay(anchorDate, hiddenDays, direction, false)
}

export function getRangeLabel(
  anchorDate: Date,
  view: CalendarView,
  options: VisibleRangeOptions = {}
) {
  const range = getVisibleRange(anchorDate, view, options)
  const visibleDays = getVisibleDaysInRange(range, options.hiddenDays)
  const labelStart = visibleDays[0] ?? range.start
  const labelEnd = visibleDays[visibleDays.length - 1] ?? range.end

  if (view === "month") {
    return formatMonthYearLabel(anchorDate, options)
  }

  if (view === "day") {
    return formatLongDateLabel(
      getNextVisibleDay(anchorDate, options.hiddenDays),
      options
    )
  }

  if (view === "agenda") {
    return formatRangeDateLabel(labelStart, labelEnd, options)
  }

  const sameMonth = isSameMonth(labelStart, labelEnd)

  if (sameMonth) {
    return `${formatMonthDayLabel(labelStart, options)} - ${formatDayNumber(labelEnd, options)}, ${formatYearLabel(labelEnd, options)}`
  }

  return formatRangeDateLabel(labelStart, labelEnd, options)
}

export function getMonthDays(
  anchorDate: Date,
  weekStartsOn: CalendarWeekday,
  hiddenDays?: CalendarWeekday[]
) {
  const range = getVisibleRange(anchorDate, "month", { weekStartsOn })

  return getVisibleDaysInRange(range, hiddenDays)
}

export function getWeekDays(
  anchorDate: Date,
  weekStartsOn: CalendarWeekday,
  hiddenDays?: CalendarWeekday[]
) {
  const start = startOfWeek(anchorDate, { weekStartsOn })

  return Array.from({ length: 7 }, (_, index) => addDays(start, index)).filter(
    (day) => !isHiddenDay(day, hiddenDays)
  )
}

export function getAgendaDays(
  range: CalendarVisibleRange,
  hiddenDays?: CalendarWeekday[]
) {
  return getVisibleDaysInRange(range, hiddenDays)
}

function mergeMinuteSegments(segments: MinuteSegment[]) {
  if (segments.length === 0) {
    return []
  }

  const sortedSegments = [...segments].sort(
    (left, right) => left.startMinute - right.startMinute
  )
  const mergedSegments = [sortedSegments[0]]

  for (const segment of sortedSegments.slice(1)) {
    const previousSegment = mergedSegments[mergedSegments.length - 1]

    if (segment.startMinute <= previousSegment.endMinute) {
      previousSegment.endMinute = Math.max(
        previousSegment.endMinute,
        segment.endMinute
      )
      continue
    }

    mergedSegments.push({ ...segment })
  }

  return mergedSegments
}

export function normalizeBusinessHours(
  businessHours?: CalendarBusinessHoursWindow[]
) {
  return (businessHours ?? [])
    .map((window) => {
      const startMinute = parseTimeStringToMinuteOfDay(window.start)
      const endMinute = parseTimeStringToMinuteOfDay(window.end)

      if (
        startMinute === null ||
        endMinute === null ||
        startMinute >= endMinute
      ) {
        return null
      }

      return {
        days:
          window.days?.length
            ? Array.from(new Set(window.days))
            : allWeekdays,
        endMinute,
        startMinute,
      }
    })
    .filter((window): window is NonNullable<typeof window> => window !== null)
}

export function getBusinessHourSegmentsForDay(
  day: Date,
  businessHours: CalendarBusinessHoursWindow[] | undefined,
  minMinute: number,
  maxMinute: number
) {
  const weekday = getDay(day) as CalendarWeekday

  return mergeMinuteSegments(
    normalizeBusinessHours(businessHours)
      .filter((window) => window.days.includes(weekday))
      .map((window) => ({
        endMinute: Math.min(maxMinute, window.endMinute),
        startMinute: Math.max(minMinute, window.startMinute),
      }))
      .filter((segment) => segment.endMinute > segment.startMinute)
  )
}

export function getOutsideBusinessHourSegmentsForDay(
  day: Date,
  businessHours: CalendarBusinessHoursWindow[] | undefined,
  minMinute: number,
  maxMinute: number
) {
  if (!businessHours?.length) {
    return []
  }

  const businessHourSegments = getBusinessHourSegmentsForDay(
    day,
    businessHours,
    minMinute,
    maxMinute
  )

  if (businessHourSegments.length === 0) {
    return [
      {
        endMinute: maxMinute,
        startMinute: minMinute,
      },
    ]
  }

  const outsideSegments: MinuteSegment[] = []
  let cursor = minMinute

  for (const segment of businessHourSegments) {
    if (segment.startMinute > cursor) {
      outsideSegments.push({
        endMinute: segment.startMinute,
        startMinute: cursor,
      })
    }

    cursor = segment.endMinute
  }

  if (cursor < maxMinute) {
    outsideSegments.push({
      endMinute: maxMinute,
      startMinute: cursor,
    })
  }

  return outsideSegments
}

export function getBlockedSegmentsForDay(
  day: Date,
  blockedRanges: CalendarBlockedRange[] | undefined,
  minMinute: number,
  maxMinute: number
) {
  const dayStart = startOfDay(day)
  const dayEnd = endOfDay(day)

  return (blockedRanges ?? []).flatMap((range) => {
      if (
        !intervalsOverlap(range.start, range.end, dayStart, addDays(dayStart, 1))
      ) {
        return []
      }

      const clippedStart = new Date(
        Math.max(range.start.getTime(), dayStart.getTime())
      )
      const clippedEnd = new Date(Math.min(range.end.getTime(), dayEnd.getTime()))
      const startMinute = Math.max(minMinute, getMinuteOfDay(clippedStart))
      const endMinute = Math.min(
        maxMinute,
        Math.max(startMinute + 1, getMinuteOfDay(clippedEnd))
      )

      if (endMinute <= startMinute) {
        return []
      }

      return [
        {
          color: range.color,
          endMinute,
          id: range.id,
          label: range.label,
          startMinute,
        } satisfies DayTimeSegment,
      ]
    })
}

export function intervalOverlapsBlockedRanges(
  start: Date,
  end: Date,
  blockedRanges?: CalendarBlockedRange[]
) {
  return (blockedRanges ?? []).some((range) =>
    intervalsOverlap(start, end, range.start, range.end)
  )
}

export function copyTimeParts(targetDay: Date, sourceDate: Date) {
  return set(targetDay, {
    hours: sourceDate.getHours(),
    minutes: sourceDate.getMinutes(),
    seconds: sourceDate.getSeconds(),
    milliseconds: sourceDate.getMilliseconds(),
  })
}

export function setMinuteOfDay(day: Date, minuteOfDay: number) {
  const hours = Math.floor(minuteOfDay / 60)
  const minutes = minuteOfDay % 60

  return set(day, {
    hours,
    minutes,
    seconds: 0,
    milliseconds: 0,
  })
}

function getMinuteOfDay(date: Date) {
  return date.getHours() * 60 + date.getMinutes()
}

function getDateTimeFormatter(
  options: Intl.DateTimeFormatOptions,
  config: CalendarDateTimeFormatOptions = {}
) {
  return new Intl.DateTimeFormat(config.locale, {
    ...options,
    ...(config.timeZone ? { timeZone: config.timeZone } : {}),
    ...(config.hourCycle
      ? { hour12: config.hourCycle === 12 }
      : {}),
  })
}

function formatMonthYearLabel(
  date: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      month: "long",
      year: "numeric",
    },
    options
  ).format(date)
}

export function formatMonthDayLabel(
  date: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      day: "numeric",
      month: "short",
    },
    options
  ).format(date)
}

function formatLongDateLabel(
  date: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      day: "numeric",
      month: "long",
      weekday: "long",
    },
    options
  ).format(date)
}

function formatYearLabel(
  date: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      year: "numeric",
    },
    options
  ).format(date)
}

function formatRangeDateLabel(
  start: Date,
  end: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  if (isSameYear(start, end)) {
    if (isSameMonth(start, end)) {
      return `${formatMonthDayLabel(start, options)} - ${formatDayNumber(end, options)}, ${formatYearLabel(end, options)}`
    }

    return `${formatMonthDayLabel(start, options)} - ${formatMonthDayLabel(end, options)}, ${formatYearLabel(end, options)}`
  }

  return `${formatMonthDayLabel(start, options)} - ${getDateTimeFormatter(
    {
      day: "numeric",
      month: "short",
      year: "numeric",
    },
    options
  ).format(end)}`
}

export function formatHourLabel(
  date: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      hour: options.hourCycle === 24 ? "2-digit" : "numeric",
    },
    options
  ).format(date)
}

function formatTimeRange(
  start: Date,
  end: Date,
  options: CalendarDateTimeFormatOptions = {},
  includeTimeZone = false
) {
  const formatter = getDateTimeFormatter(
    {
      hour: options.hourCycle === 24 ? "2-digit" : "numeric",
      minute: "2-digit",
    },
    options
  )

  const label = `${formatter.format(start)} - ${formatter.format(end)}`

  if (!includeTimeZone || !options.timeZone) {
    return label
  }

  return `${label} ${options.timeZone}`
}

export function getOccurrenceAccentColor(
  occurrence: CalendarOccurrence,
  index = 0
) {
  if (occurrence.color) {
    return occurrence.color
  }

  const seed = hashString(
    occurrence.calendarId ?? occurrence.resourceId ?? occurrence.id
  )

  return fallbackEventColors[(seed + index) % fallbackEventColors.length]
}

export function expandOccurrences(
  events: CalendarEvent[],
  range: CalendarVisibleRange
) {
  const occurrences: CalendarOccurrence[] = []

  for (const event of events) {
    if (event.archived) {
      continue
    }

    if (!event.recurrence) {
      if (intersectsRange(event.start, event.end, range.start, range.end)) {
        occurrences.push({
          ...event,
          occurrenceId: event.id,
          sourceEventId: event.id,
          isRecurringInstance: false,
          seriesIndex: 0,
        })
      }

      continue
    }

    occurrences.push(
      ...expandRecurringEvent(event, {
        rangeStart: range.start,
        rangeEnd: range.end,
      })
    )
  }

  return occurrences.sort((left, right) => {
    if (left.start.getTime() === right.start.getTime()) {
      return left.end.getTime() - right.end.getTime()
    }

    return left.start.getTime() - right.start.getTime()
  })
}

function expandRecurringEvent(
  event: CalendarEvent,
  context: RecurrenceCursorContext
) {
  const interval = event.recurrence?.interval ?? 1
  const occurrences: CalendarOccurrence[] = []
  const duration = event.end.getTime() - event.start.getTime()
  const countLimit = event.recurrence?.count ?? RECURRENCE_LIMIT
  let seriesIndex = 0

  if (!event.recurrence) {
    return occurrences
  }

  if (event.recurrence.frequency === "daily") {
    let cursor = event.start

    while (seriesIndex < countLimit && seriesIndex < RECURRENCE_LIMIT) {
      const nextEnd = new Date(cursor.getTime() + duration)

      if (event.recurrence.until && cursor > event.recurrence.until) {
        break
      }

      if (
        intersectsRange(cursor, nextEnd, context.rangeStart, context.rangeEnd)
      ) {
        occurrences.push(createOccurrence(event, cursor, nextEnd, seriesIndex))
      }

      if (cursor > context.rangeEnd && !event.recurrence.until) {
        break
      }

      cursor = addDays(cursor, interval)
      seriesIndex += 1
    }

    return occurrences
  }

  if (event.recurrence.frequency === "weekly") {
    const weekdays = [
      ...(event.recurrence.byWeekday?.length
        ? event.recurrence.byWeekday
        : [getDay(event.start) as CalendarWeekday]),
    ].sort()
    let weekCursor = startOfWeek(event.start, { weekStartsOn: 0 })

    while (seriesIndex < countLimit && seriesIndex < RECURRENCE_LIMIT) {
      for (const weekday of weekdays) {
        const candidateDay = addDays(
          weekCursor,
          (weekday - getDay(weekCursor) + 7) % 7
        )
        const candidateStart = copyTimeParts(candidateDay, event.start)

        if (candidateStart < event.start) {
          continue
        }

        if (event.recurrence.until && candidateStart > event.recurrence.until) {
          return occurrences
        }

        const candidateEnd = new Date(candidateStart.getTime() + duration)

        if (
          intersectsRange(
            candidateStart,
            candidateEnd,
            context.rangeStart,
            context.rangeEnd
          )
        ) {
          occurrences.push(
            createOccurrence(event, candidateStart, candidateEnd, seriesIndex)
          )
        }

        seriesIndex += 1

        if (seriesIndex >= countLimit || seriesIndex >= RECURRENCE_LIMIT) {
          return occurrences
        }
      }

      weekCursor = addWeeks(weekCursor, interval)

      if (weekCursor > context.rangeEnd && !event.recurrence.until) {
        break
      }
    }

    return occurrences
  }

  if (event.recurrence.frequency === "monthly") {
    const monthDays = [
      ...(event.recurrence.byMonthDay?.length
        ? event.recurrence.byMonthDay
        : [event.start.getDate()]),
    ].sort((left, right) => left - right)
    let monthCursor = startOfMonth(event.start)

    while (seriesIndex < countLimit && seriesIndex < RECURRENCE_LIMIT) {
      for (const dayOfMonth of monthDays) {
        const lastDayOfMonth = endOfMonth(monthCursor).getDate()

        if (dayOfMonth > lastDayOfMonth) {
          continue
        }

        const candidateStart = copyTimeParts(
          set(monthCursor, {
            date: dayOfMonth,
            hours: 0,
            minutes: 0,
            seconds: 0,
            milliseconds: 0,
          }),
          event.start
        )

        if (candidateStart < event.start) {
          continue
        }

        if (event.recurrence.until && candidateStart > event.recurrence.until) {
          return occurrences
        }

        const candidateEnd = new Date(candidateStart.getTime() + duration)

        if (
          intersectsRange(
            candidateStart,
            candidateEnd,
            context.rangeStart,
            context.rangeEnd
          )
        ) {
          occurrences.push(
            createOccurrence(event, candidateStart, candidateEnd, seriesIndex)
          )
        }

        seriesIndex += 1

        if (seriesIndex >= countLimit || seriesIndex >= RECURRENCE_LIMIT) {
          return occurrences
        }
      }

      monthCursor = addMonths(monthCursor, interval)

      if (monthCursor > context.rangeEnd && !event.recurrence.until) {
        break
      }
    }

    return occurrences
  }

  let cursor = event.start

  while (seriesIndex < countLimit && seriesIndex < RECURRENCE_LIMIT) {
    const nextEnd = new Date(cursor.getTime() + duration)

    if (event.recurrence.until && cursor > event.recurrence.until) {
      break
    }

    if (
      intersectsRange(cursor, nextEnd, context.rangeStart, context.rangeEnd)
    ) {
      occurrences.push(createOccurrence(event, cursor, nextEnd, seriesIndex))
    }

    if (cursor > context.rangeEnd && !event.recurrence.until) {
      break
    }

    cursor = addYears(cursor, interval)
    seriesIndex += 1
  }

  return occurrences
}

function createOccurrence(
  event: CalendarEvent,
  start: Date,
  end: Date,
  seriesIndex: number
): CalendarOccurrence {
  return {
    ...event,
    start,
    end,
    occurrenceId: `${event.id}:${seriesIndex}`,
    sourceEventId: event.id,
    isRecurringInstance: true,
    seriesIndex,
  }
}

export function getDayEvents(occurrences: CalendarOccurrence[], day: Date) {
  return occurrences.filter((occurrence) =>
    intersectsRange(
      occurrence.start,
      occurrence.end,
      startOfDay(day),
      endOfDay(day)
    )
  )
}

export function getAllDayEvents(occurrences: CalendarOccurrence[], day: Date) {
  return getDayEvents(occurrences, day).filter(
    (occurrence) => occurrence.allDay
  )
}

function getTimedEvents(occurrences: CalendarOccurrence[], day: Date) {
  return getDayEvents(occurrences, day).filter(
    (occurrence) => !occurrence.allDay
  )
}

export function getDayLayout(
  occurrences: CalendarOccurrence[],
  day: Date,
  minMinute = 0,
  maxMinute = MINUTES_IN_DAY
): DayEventLayout[] {
  const segments = getTimedEvents(occurrences, day)
    .map((occurrence) => {
      const dayStart = startOfDay(day)
      const dayEnd = endOfDay(day)
      const clippedStart = new Date(
        Math.max(occurrence.start.getTime(), dayStart.getTime())
      )
      const clippedEnd = new Date(
        Math.min(occurrence.end.getTime(), dayEnd.getTime())
      )
      const startMinute = Math.max(minMinute, getMinuteOfDay(clippedStart))
      const endMinute = Math.min(
        maxMinute,
        Math.max(startMinute + 15, getMinuteOfDay(clippedEnd))
      )

      return {
        occurrence,
        startMinute,
        endMinute,
        column: 0,
        columns: 1,
      }
    })
    .filter(
      (segment) =>
        segment.endMinute > minMinute && segment.startMinute < maxMinute
    )
    .sort((left, right) => {
      if (left.startMinute === right.startMinute) {
        return left.endMinute - right.endMinute
      }

      return left.startMinute - right.startMinute
    })

  const groups: (typeof segments)[] = []
  let active: typeof segments = []
  let currentGroup: typeof segments = []

  for (const segment of segments) {
    active = active.filter((item) => item.endMinute > segment.startMinute)

    if (active.length === 0 && currentGroup.length > 0) {
      groups.push(currentGroup)
      currentGroup = []
    }

    let column = 0

    while (active.some((item) => item.column === column)) {
      column += 1
    }

    segment.column = column
    active.push(segment)
    currentGroup.push(segment)
  }

  if (currentGroup.length > 0) {
    groups.push(currentGroup)
  }

  for (const group of groups) {
    const columns = Math.max(...group.map((segment) => segment.column)) + 1

    for (const segment of group) {
      segment.columns = columns
    }
  }

  return segments.map((segment) => ({
    occurrence: segment.occurrence,
    column: segment.column,
    columns: segment.columns,
    top: segment.startMinute,
    height: Math.max(15, segment.endMinute - segment.startMinute),
  }))
}

export function applyMoveOperation(
  events: CalendarEvent[],
  operation: CalendarMoveOperation
) {
  return events.map((event) => {
    if (event.id !== operation.occurrence.sourceEventId) {
      return event
    }

    return {
      ...event,
      start: operation.nextStart,
      end: operation.nextEnd,
      allDay: operation.allDay ?? event.allDay,
    }
  })
}

export function applyResizeOperation(
  events: CalendarEvent[],
  operation: CalendarResizeOperation
) {
  return events.map((event) => {
    if (event.id !== operation.occurrence.sourceEventId) {
      return event
    }

    return {
      ...event,
      start: operation.nextStart,
      end: operation.nextEnd,
    }
  })
}

export function createEventFromOperation(
  operation: CalendarCreateOperation,
  overrides: Partial<CalendarEvent> = {}
): CalendarEvent {
  return {
    id: crypto.randomUUID(),
    title: operation.title ?? overrides.title ?? "New event",
    start: operation.start,
    end: operation.end,
    allDay: operation.allDay,
    archived: overrides.archived,
    color: operation.color ?? overrides.color,
    calendarId: operation.calendarId ?? overrides.calendarId,
    calendarLabel: operation.calendarLabel ?? overrides.calendarLabel,
    timeZone: operation.timeZone ?? overrides.timeZone,
    resourceId: operation.resourceId ?? overrides.resourceId,
    description: operation.description ?? overrides.description,
    location: operation.location ?? overrides.location,
    readOnly: operation.readOnly ?? overrides.readOnly,
    data: operation.data ?? overrides.data,
  }
}

export function duplicateOccurrenceAsEvent(
  occurrence: CalendarOccurrence
): CalendarEvent {
  const durationMs = occurrence.end.getTime() - occurrence.start.getTime()
  const nextStart = occurrence.allDay
    ? addDays(occurrence.start, getDaySpan(occurrence))
    : addMinutes(occurrence.end, 30)
  const nextEnd = new Date(nextStart.getTime() + durationMs)

  return {
    id: crypto.randomUUID(),
    title: occurrence.title,
    start: nextStart,
    end: nextEnd,
    allDay: occurrence.allDay,
    archived: false,
    color: occurrence.color,
    calendarId: occurrence.calendarId,
    calendarLabel: occurrence.calendarLabel,
    timeZone: occurrence.timeZone,
    recurrence: undefined,
    resourceId: occurrence.resourceId,
    description: occurrence.description,
    location: occurrence.location,
    readOnly: false,
    data: occurrence.data,
  }
}

export function clampResize(
  nextDate: Date,
  oppositeDate: Date,
  edge: "start" | "end",
  minimumMinutes: number
) {
  if (edge === "start") {
    const latestStart = addMinutes(oppositeDate, -minimumMinutes)

    if (nextDate > latestStart) {
      return latestStart
    }

    return nextDate
  }

  const earliestEnd = addMinutes(oppositeDate, minimumMinutes)

  if (nextDate < earliestEnd) {
    return earliestEnd
  }

  return nextDate
}

function intersectsRange(
  start: Date,
  end: Date,
  rangeStart: Date,
  rangeEnd: Date
) {
  return (
    start.getTime() <= rangeEnd.getTime() &&
    end.getTime() >= rangeStart.getTime()
  )
}

function intervalsOverlap(
  start: Date,
  end: Date,
  rangeStart: Date,
  rangeEnd: Date
) {
  return (
    start.getTime() < rangeEnd.getTime() && end.getTime() > rangeStart.getTime()
  )
}

function hashString(value: string) {
  return value.split("").reduce((result, character) => {
    return character.charCodeAt(0) + ((result << 5) - result)
  }, 0)
}

export function getDaySpan(event: Pick<CalendarEvent, "start" | "end">) {
  return Math.max(
    1,
    Math.ceil(
      (event.end.getTime() - event.start.getTime()) / MILLISECONDS_IN_DAY
    )
  )
}

export function getEventMetaLabel(
  event: CalendarOccurrence,
  options: CalendarDateTimeFormatOptions = {}
) {
  if (event.allDay) {
    return "All day"
  }

  return formatTimeRange(event.start, event.end, {
    ...options,
    timeZone: options.timeZone ?? event.timeZone,
  })
}

export function formatDayNumber(
  day: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      day: "numeric",
    },
    options
  ).format(day)
}

export function formatWeekday(
  day: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return getDateTimeFormatter(
    {
      weekday: "short",
    },
    options
  ).format(day)
}

export function formatAgendaHeading(
  day: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return formatLongDateLabel(day, options)
}

export function formatAgendaEyebrow(
  day: Date,
  options: CalendarDateTimeFormatOptions = {}
) {
  return formatWeekday(day, options)
}

export function isOutsideMonth(day: Date, anchorDate: Date) {
  return !isSameMonth(day, anchorDate)
}

export function isToday(day: Date) {
  return isSameDay(day, new Date())
}

"use client"

import * as React from "react"
import { createPortal } from "react-dom"

import {
  DndContext,
  DragOverlay,
  PointerSensor,
  pointerWithin,
  useSensor,
  useSensors,
  type ClientRect,
  type CollisionDetection,
  type DragEndEvent,
  type DragStartEvent,
} from "@dnd-kit/core"
import { addDays, addMinutes, startOfDay } from "date-fns"

import type {
  CalendarCreateOperation,
  CalendarDragData,
  CalendarEvent,
  CalendarEventChangeConfirmationContext,
  CalendarDropTarget,
  CalendarMoveOperation,
  CalendarOccurrence,
  CalendarResizeOperation,
} from "../../types"
import {
  applyMoveOperation,
  applyResizeOperation,
  clampResize,
  copyTimeParts,
  expandOccurrences,
  getNextVisibleDay,
  getCalendarSlotClassName,
  getDaySpan,
  getEventMetaLabel,
  getRangeLabel,
  getVisibleRange,
  intervalOverlapsBlockedRanges,
  normalizeAvailableViews,
  normalizeHiddenDays,
  resolveCalendarView,
  setMinuteOfDay,
  shiftDate,
} from "../../utils"
import { CalendarAgendaView } from "./agenda-view"
import { EventSurface, getResolvedAccentColor } from "./event-card"
import { CalendarMonthView } from "./month-view"
import { CalendarToolbar } from "./toolbar"
import { CalendarDayView, CalendarWeekView } from "./time-grid-view"
import {
  compactSlotHeight,
  defaultMaxHour,
  defaultMinHour,
  defaultSlotDuration,
  slotHeight as defaultSlotHeight,
  type CalendarEventMenuPosition,
  type CalendarRootProps,
  type SharedViewProps,
} from "../shared"
import { CalendarEventChangeConfirmationDialog } from "./event-change-confirmation-dialog"
import { CalendarEventCreateSheet } from "./event-create-sheet"
import { CalendarEventContextMenu } from "./event-context-menu"

export function CalendarRoot({
  agendaDays = 14,
  availableViews,
  blockedRanges,
  businessHours,
  classNames,
  createEventSheet,
  date,
  density = "comfortable",
  eventChangeConfirmation,
  events,
  getEventColor,
  hiddenDays,
  hourCycle,
  locale,
  maxHour = defaultMaxHour,
  minHour = defaultMinHour,
  onDateChange,
  onEventArchive,
  onEventCreate,
  onEventDelete,
  onEventDuplicate,
  onEventMove,
  onEventResize,
  onEventSelect,
  onNavigate,
  onSelectedEventChange,
  onToday,
  onViewChange,
  renderEvent,
  resources,
  scrollToTime,
  selectedEventId,
  slotDuration = defaultSlotDuration,
  slotHeight: customSlotHeight,
  timeZone,
  view,
  weekStartsOn = 1,
}: CalendarRootProps) {
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 6,
      },
    })
  )
  const [optimisticEvents, setOptimisticEvents] =
    React.useState<CalendarEvent[]>(events)
  const resolvedAvailableViews = React.useMemo(
    () => normalizeAvailableViews(availableViews),
    [availableViews]
  )
  const resolvedHiddenDays = React.useMemo(
    () => normalizeHiddenDays(hiddenDays),
    [hiddenDays]
  )
  const resolvedView = React.useMemo(
    () => resolveCalendarView(view, resolvedAvailableViews),
    [resolvedAvailableViews, view]
  )
  const resolvedSlotHeight =
    customSlotHeight ??
    (density === "compact" ? compactSlotHeight : defaultSlotHeight)
  const range = getVisibleRange(date, resolvedView, {
    agendaDays,
    hiddenDays: resolvedHiddenDays,
    hourCycle,
    locale,
    timeZone,
    weekStartsOn,
  })
  const [isHydrated, setIsHydrated] = React.useState(false)
  const [activeDrag, setActiveDrag] = React.useState<CalendarDragData | null>(
    null
  )
  const [activeDropTarget, setActiveDropTarget] =
    React.useState<CalendarDropTarget | null>(null)
  const lastDropTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const [activeDragOffsetMinutes, setActiveDragOffsetMinutes] =
    React.useState(0)
  const [activeResize, setActiveResize] = React.useState<{
    edge: "start" | "end"
    occurrence: CalendarOccurrence
    pointerId: number
  } | null>(null)
  const [activeResizeTarget, setActiveResizeTarget] =
    React.useState<CalendarDropTarget | null>(null)
  const activeResizeTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const lastResizeTargetRef = React.useRef<CalendarDropTarget | null>(null)
  const [activeDragRect, setActiveDragRect] = React.useState<ClientRect | null>(
    null
  )
  const [contextMenu, setContextMenu] = React.useState<{
    occurrence: CalendarOccurrence
    position: CalendarEventMenuPosition
  } | null>(null)
  const [pendingEventChange, setPendingEventChange] =
    React.useState<CalendarEventChangeConfirmationContext | null>(null)
  const [createSheetOperation, setCreateSheetOperation] =
    React.useState<CalendarCreateOperation | null>(null)
  const [liveAnnouncement, setLiveAnnouncement] = React.useState("")

  React.useEffect(() => {
    setIsHydrated(true)
  }, [])

  React.useLayoutEffect(() => {
    setOptimisticEvents(events)
  }, [events])

  function updateActiveResizeTarget(target: CalendarDropTarget | null) {
    activeResizeTargetRef.current = target
    setActiveResizeTarget(target)

    if (target) {
      lastResizeTargetRef.current = target
    }
  }

  function clearActiveResize() {
    setActiveResize(null)
    updateActiveResizeTarget(null)
    lastResizeTargetRef.current = null
  }

  const shouldBlockTimedRange = React.useCallback(
    (start: Date, end: Date, allDay: boolean | undefined) => {
      if (
        allDay ||
        resolvedView === "month" ||
        resolvedView === "agenda" ||
        !blockedRanges?.length
      ) {
        return false
      }

      return intervalOverlapsBlockedRanges(start, end, blockedRanges)
    },
    [blockedRanges, resolvedView]
  )

  const previewOccurrence = React.useMemo(() => {
    if (activeResize && activeResizeTarget) {
      const operation = getResizeOperation(
        activeResize.occurrence,
        activeResize.edge,
        activeResizeTarget,
        slotDuration
      )

      if (
        shouldBlockTimedRange(
          operation.nextStart,
          operation.nextEnd,
          activeResize.occurrence.allDay
        )
      ) {
        return null
      }

      return {
        ...activeResize.occurrence,
        start: operation.nextStart,
        end: operation.nextEnd,
      }
    }

    if (!activeDrag || !activeDropTarget) {
      return null
    }

    const nextPreviewOccurrence = getPreviewOccurrence(
      activeDrag,
      activeDropTarget,
      slotDuration,
      activeDragOffsetMinutes
    )
    const previewAllDay =
      activeDrag.kind === "event"
        ? nextPreviewOccurrence.allDay
        : activeDrag.occurrence.allDay

    if (
      shouldBlockTimedRange(
        nextPreviewOccurrence.start,
        nextPreviewOccurrence.end,
        previewAllDay
      )
    ) {
      return null
    }

    return nextPreviewOccurrence
  }, [
    activeDrag,
    activeDragOffsetMinutes,
    activeDropTarget,
    activeResize,
    activeResizeTarget,
    shouldBlockTimedRange,
    slotDuration,
  ])

  const occurrences = React.useMemo(() => {
    const nextOccurrences = expandOccurrences(optimisticEvents, range)

    if (!previewOccurrence || !activeResize) {
      return nextOccurrences
    }

    return nextOccurrences.map((occurrence) =>
      occurrence.occurrenceId === previewOccurrence.occurrenceId
        ? previewOccurrence
        : occurrence
    )
  }, [activeResize, optimisticEvents, previewOccurrence, range])

  function announce(message: string) {
    setLiveAnnouncement(message)
  }

  function handleSelectEvent(occurrence: CalendarOccurrence) {
    setContextMenu(null)
    onSelectedEventChange?.(occurrence.occurrenceId)
    onEventSelect?.(occurrence)
  }

  function closeContextMenu() {
    setContextMenu(null)
  }

  function closeCreateSheet() {
    setCreateSheetOperation(null)
  }

  function closePendingEventChange() {
    setPendingEventChange(null)
  }

  function handleOpenContextMenu(
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) {
    const canMutate = !occurrence.readOnly
    const hasActions =
      !!onEventDuplicate || (canMutate && (!!onEventArchive || !!onEventDelete))

    if (!hasActions) {
      return
    }

    handleSelectEvent(occurrence)
    setContextMenu({
      occurrence,
      position,
    })
  }

  function handleNavigate(direction: -1 | 1) {
    if (onNavigate) {
      onNavigate(direction)
      return
    }

    onDateChange(shiftDate(date, resolvedView, direction, resolvedHiddenDays))
  }

  function handleToday() {
    if (onToday) {
      onToday()
      return
    }

    onDateChange(new Date())
  }

  function getDefaultCreateOperation(
    operation: CalendarCreateOperation
  ): CalendarCreateOperation {
    const defaultResource = resources?.[0]

    return {
      calendarId: operation.calendarId ?? defaultResource?.id,
      calendarLabel: operation.calendarLabel ?? defaultResource?.label,
      color: operation.color ?? defaultResource?.color,
      resourceId: operation.resourceId ?? defaultResource?.id,
      timeZone: operation.timeZone ?? timeZone,
      ...operation,
    }
  }

  function commitCreateEvent(operation: CalendarCreateOperation) {
    if (!onEventCreate) {
      return
    }

    if (shouldBlockTimedRange(operation.start, operation.end, operation.allDay)) {
      announce("Blocked time is unavailable.")
      return "Blocked time is unavailable."
    }

    onEventCreate(operation)
    onSelectedEventChange?.(undefined)
    announce(`Created ${operation.title ?? "a new appointment"}.`)
  }

  function requestEventCreate(operation: CalendarCreateOperation) {
    if (!onEventCreate) {
      return
    }

    const nextOperation = getDefaultCreateOperation(operation)

    if (
      shouldBlockTimedRange(
        nextOperation.start,
        nextOperation.end,
        nextOperation.allDay
      )
    ) {
      announce("Blocked time is unavailable.")
      return
    }

    const shouldOpenSheet =
      createEventSheet !== undefined && createEventSheet !== false

    if (shouldOpenSheet) {
      closeContextMenu()
      setCreateSheetOperation(nextOperation)
      return
    }

    commitCreateEvent(nextOperation)
  }

  function shouldConfirmEventChange(
    context: CalendarEventChangeConfirmationContext
  ) {
    if (!eventChangeConfirmation) {
      return false
    }

    if (typeof eventChangeConfirmation === "boolean") {
      return eventChangeConfirmation
    }

    return eventChangeConfirmation.shouldConfirm?.(context) ?? true
  }

  function commitEventChange(context: CalendarEventChangeConfirmationContext) {
    if (context.action === "move") {
      const operation: CalendarMoveOperation = {
        allDay: context.allDay,
        nextEnd: context.nextEnd,
        nextStart: context.nextStart,
        occurrence: context.occurrence,
        previousEnd: context.previousEnd,
        previousStart: context.previousStart,
      }

      setOptimisticEvents((currentEvents) =>
        applyMoveOperation(currentEvents, operation)
      )
      onEventMove?.(operation)
      announce(`Moved ${context.occurrence.title}.`)
      return
    }

    const operation: CalendarResizeOperation = {
      edge: context.edge,
      nextEnd: context.nextEnd,
      nextStart: context.nextStart,
      occurrence: context.occurrence,
      previousEnd: context.previousEnd,
      previousStart: context.previousStart,
    }

    setOptimisticEvents((currentEvents) =>
      applyResizeOperation(currentEvents, operation)
    )
    onEventResize?.(operation)
    announce(`Resized ${context.occurrence.title}.`)
  }

  function requestEventChange(
    context: CalendarEventChangeConfirmationContext
  ) {
    closeContextMenu()

    const allDay =
      context.action === "move"
        ? context.allDay ?? context.occurrence.allDay
        : context.occurrence.allDay

    if (shouldBlockTimedRange(context.nextStart, context.nextEnd, allDay)) {
      announce("Blocked time is unavailable.")
      return
    }

    if (shouldConfirmEventChange(context)) {
      setPendingEventChange(context)
      return
    }

    commitEventChange(context)
  }

  function handleQuickCreate() {
    if (!onEventCreate) {
      return
    }

    const quickCreateDay = getNextVisibleDay(date, resolvedHiddenDays)
    const start = setMinuteOfDay(
      startOfDay(quickCreateDay),
      Math.max(minHour * 60, 9 * 60)
    )

    requestEventCreate({
      start,
      end: addMinutes(start, 60),
    })
  }

  function moveOccurrenceWithTarget(
    occurrence: CalendarOccurrence,
    target: CalendarDropTarget,
    dragOffsetMinutes = 0
  ) {
    if (!onEventMove) {
      return
    }

    const operation = getMoveOperation(occurrence, target, dragOffsetMinutes)
    requestEventChange({
      action: "move",
      ...operation,
    })
  }

  function resizeOccurrenceWithTarget(
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    target: CalendarDropTarget
  ) {
    if (!onEventResize) {
      return
    }

    const operation = getResizeOperation(occurrence, edge, target, slotDuration)
    requestEventChange({
      action: "resize",
      ...operation,
    })
  }

  function handleResizeHandlePointerDown(
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: React.PointerEvent<HTMLSpanElement>
  ) {
    if (!onEventResize) {
      return
    }

    closeContextMenu()
    setActiveResize({
      edge,
      occurrence,
      pointerId: event.pointerId,
    })
    updateActiveResizeTarget(
      getTimeGridDropTargetFromPoint(event.clientX, event.clientY)
    )
  }

  const commitPointerResize = React.useEffectEvent(
    (
      resize: NonNullable<typeof activeResize>,
      target: CalendarDropTarget
    ) => {
      resizeOccurrenceWithTarget(resize.occurrence, resize.edge, target)
    }
  )
  const clearPointerResize = React.useEffectEvent(() => {
    clearActiveResize()
  })

  React.useEffect(() => {
    if (!activeResize) {
      return
    }

    const resize = activeResize

    function handlePointerMove(event: PointerEvent) {
      if (event.pointerId !== resize.pointerId) {
        return
      }

      updateActiveResizeTarget(
        getTimeGridDropTargetFromPoint(event.clientX, event.clientY)
      )
    }

    function handlePointerUp(event: PointerEvent) {
      if (event.pointerId !== resize.pointerId) {
        return
      }

      const target =
        getTimeGridDropTargetFromPoint(event.clientX, event.clientY) ??
        activeResizeTargetRef.current ??
        lastResizeTargetRef.current

      if (!target) {
        clearPointerResize()
        return
      }

      commitPointerResize(resize, target)
      clearPointerResize()
    }

    function handlePointerCancel(event: PointerEvent) {
      if (event.pointerId !== resize.pointerId) {
        return
      }

      clearPointerResize()
    }

    window.addEventListener("pointermove", handlePointerMove)
    window.addEventListener("pointerup", handlePointerUp)
    window.addEventListener("pointercancel", handlePointerCancel)

    return () => {
      window.removeEventListener("pointermove", handlePointerMove)
      window.removeEventListener("pointerup", handlePointerUp)
      window.removeEventListener("pointercancel", handlePointerCancel)
    }
  }, [activeResize])

  function handleDragStart(event: DragStartEvent) {
    const dragData = isCalendarDragData(event.active.data.current)
      ? event.active.data.current
      : undefined

    if (!dragData) {
      return
    }

    closeContextMenu()
    setActiveDrag(dragData)
    setActiveDropTarget(null)
    lastDropTargetRef.current = null
    const dragSurfaceRect = getDragSurfaceRect(event.activatorEvent.target)
    const nextDragRect = dragSurfaceRect ?? event.active.rect.current.initial

    setActiveDragRect(nextDragRect)
    setActiveDragOffsetMinutes(
      getDragOffsetMinutes(dragData, nextDragRect, event.activatorEvent)
    )
  }

  function handleDragEnd(event: DragEndEvent) {
    const dragData = isCalendarDragData(event.active.data.current)
      ? event.active.data.current
      : undefined
    const target =
      (isCalendarDropTarget(event.over?.data.current)
        ? event.over?.data.current
        : undefined) ??
      activeDropTarget ??
      lastDropTargetRef.current ??
      undefined
    const dragOffsetMinutes = activeDragOffsetMinutes

    setActiveDrag(null)
    setActiveDropTarget(null)
    setActiveDragOffsetMinutes(0)
    setActiveDragRect(null)
    lastDropTargetRef.current = null

    if (!dragData || !target) {
      return
    }

    if (dragData.kind === "event") {
      moveOccurrenceWithTarget(dragData.occurrence, target, dragOffsetMinutes)
      return
    }

    resizeOccurrenceWithTarget(dragData.occurrence, dragData.edge, target)
  }

  function getDragSurfaceRect(target: EventTarget | null): ClientRect | null {
    if (!(target instanceof Element)) {
      return null
    }

    return (
      target
        .closest<HTMLElement>("[data-calendar-drag-surface]")
        ?.getBoundingClientRect() ?? null
    )
  }

  function handleDragCancel() {
    setActiveDrag(null)
    setActiveDropTarget(null)
    setActiveDragOffsetMinutes(0)
    setActiveDragRect(null)
    lastDropTargetRef.current = null
    closeContextMenu()
  }

  function handleDuplicateEvent(occurrence: CalendarOccurrence) {
    onEventDuplicate?.(occurrence)
    onSelectedEventChange?.(undefined)
    closeContextMenu()
    announce(`Duplicated ${occurrence.title}.`)
  }

  function handleArchiveEvent(occurrence: CalendarOccurrence) {
    onEventArchive?.(occurrence)
    onSelectedEventChange?.(undefined)
    closeContextMenu()
    announce(`Archived ${occurrence.title}.`)
  }

  function handleDeleteEvent(occurrence: CalendarOccurrence) {
    onEventDelete?.(occurrence)
    onSelectedEventChange?.(undefined)
    closeContextMenu()
    announce(`Deleted ${occurrence.title}.`)
  }

  function handleConfirmPendingEventChange() {
    if (!pendingEventChange) {
      return
    }

    commitEventChange(pendingEventChange)
    closePendingEventChange()
  }

  function handleEventKeyCommand(
    occurrence: CalendarOccurrence,
    event: React.KeyboardEvent<HTMLButtonElement>
  ) {
    const dayDelta =
      event.key === "ArrowLeft" ? -1 : event.key === "ArrowRight" ? 1 : 0
    const minuteDelta =
      event.key === "ArrowUp"
        ? -slotDuration
        : event.key === "ArrowDown"
          ? slotDuration
          : 0

    if (dayDelta === 0 && minuteDelta === 0) {
      return
    }

    event.preventDefault()

    if (event.shiftKey && onEventResize) {
      const operation: CalendarResizeOperation = {
        occurrence,
        edge: "end",
        nextStart: occurrence.start,
        nextEnd: clampResize(
          addMinutes(addDays(occurrence.end, dayDelta), minuteDelta),
          occurrence.start,
          "end",
          slotDuration
        ),
        previousStart: occurrence.start,
        previousEnd: occurrence.end,
      }

      requestEventChange({
        action: "resize",
        ...operation,
      })
      return
    }

    if (event.altKey && onEventResize) {
      const operation: CalendarResizeOperation = {
        occurrence,
        edge: "start",
        nextStart: clampResize(
          addMinutes(addDays(occurrence.start, dayDelta), minuteDelta),
          occurrence.end,
          "start",
          slotDuration
        ),
        nextEnd: occurrence.end,
        previousStart: occurrence.start,
        previousEnd: occurrence.end,
      }

      requestEventChange({
        action: "resize",
        ...operation,
      })
      return
    }

    if (!onEventMove) {
      return
    }

    const operation: CalendarMoveOperation = {
      occurrence,
      nextStart: addMinutes(addDays(occurrence.start, dayDelta), minuteDelta),
      nextEnd: addMinutes(addDays(occurrence.end, dayDelta), minuteDelta),
      previousStart: occurrence.start,
      previousEnd: occurrence.end,
      allDay: occurrence.allDay,
    }

    requestEventChange({
      action: "move",
      ...operation,
    })
  }

  const currentLabel = getRangeLabel(date, resolvedView, {
    agendaDays,
    hiddenDays: resolvedHiddenDays,
    hourCycle,
    locale,
    timeZone,
    weekStartsOn,
  })
  const sharedViewProps: SharedViewProps = {
    anchorDate: date,
    blockedRanges,
    businessHours,
    classNames,
    density,
    dragPreviewOccurrence:
      activeDrag?.kind === "event" ? previewOccurrence ?? undefined : undefined,
    getEventColor,
    hiddenDays: resolvedHiddenDays,
    hourCycle,
    interactive: isHydrated,
    locale,
    occurrences,
    previewOccurrenceId: activeResize ? previewOccurrence?.occurrenceId : undefined,
    onEventCreate: onEventCreate ? requestEventCreate : undefined,
    onEventKeyCommand: handleEventKeyCommand,
    onResizeHandlePointerDown: handleResizeHandlePointerDown,
    onOpenContextMenu: handleOpenContextMenu,
    onSelectEvent: handleSelectEvent,
    renderEvent,
    scrollToTime,
    selectedEventId,
    slotDuration,
    slotHeight: resolvedSlotHeight,
    timeZone,
    weekStartsOn,
  }
  const collisionDetection = React.useCallback<CollisionDetection>((args) => {
    return pointerWithin(args)
  }, [])
  const portals = (
    <>
      <DragOverlay>
        {activeDrag?.kind === "event" ? (
          <EventSurface
            accentColor={getResolvedAccentColor(
              activeDrag.occurrence,
              getEventColor
            )}
            className={getCalendarSlotClassName(
              classNames,
              "dragOverlay",
              activeDragRect ? undefined : "w-64 max-w-[80vw]"
            )}
            density={density}
            event={activeDrag.occurrence}
            overlay
            renderEvent={renderEvent}
            style={
              activeDragRect
                ? {
                    width: activeDragRect.width,
                    height: activeDragRect.height,
                  }
                : undefined
            }
            timeLabel={getEventMetaLabel(activeDrag.occurrence, {
              hourCycle,
              locale,
              timeZone,
            })}
            variant={activeDrag.variant}
          />
        ) : null}
      </DragOverlay>
      {contextMenu ? (
        <CalendarEventContextMenu
          hourCycle={hourCycle}
          locale={locale}
          occurrence={contextMenu.occurrence}
          onArchive={
            !contextMenu.occurrence.readOnly && onEventArchive
              ? () => handleArchiveEvent(contextMenu.occurrence)
              : undefined
          }
          onClose={closeContextMenu}
          onDelete={
            !contextMenu.occurrence.readOnly && onEventDelete
              ? () => handleDeleteEvent(contextMenu.occurrence)
              : undefined
          }
          onDuplicate={
            onEventDuplicate
              ? () => handleDuplicateEvent(contextMenu.occurrence)
              : undefined
          }
          timeZone={timeZone}
          x={contextMenu.position.x}
          y={contextMenu.position.y}
        />
      ) : null}
      <CalendarEventChangeConfirmationDialog
        config={eventChangeConfirmation}
        context={pendingEventChange}
        hourCycle={hourCycle}
        locale={locale}
        onCancel={closePendingEventChange}
        onConfirm={handleConfirmPendingEventChange}
        timeZone={timeZone}
      />
      <CalendarEventCreateSheet
        config={createEventSheet}
        initialOperation={createSheetOperation}
        onOpenChange={(open) => {
          if (!open) {
            closeCreateSheet()
          }
        }}
        onSubmit={commitCreateEvent}
        resources={resources}
        timeZone={timeZone}
      />
    </>
  )

  return (
    <div
      className={getCalendarSlotClassName(
        classNames,
        "root",
        "flex min-h-[42rem] flex-col overflow-hidden rounded-[calc(var(--radius)*1.6)] border border-border/70 bg-background shadow-[0_20px_80px_-48px_rgba(15,23,42,0.55)]"
      )}
      data-testid="calendar-root"
    >
      <CalendarToolbar
        availableViews={resolvedAvailableViews}
        classNames={classNames}
        currentLabel={currentLabel}
        density={density}
        onNavigate={handleNavigate}
        onQuickCreate={onEventCreate ? handleQuickCreate : undefined}
        onToday={handleToday}
        onViewChange={onViewChange}
        resources={resources}
        timeZone={timeZone}
        view={resolvedView}
      />
      <DndContext
        collisionDetection={collisionDetection}
        onDragCancel={handleDragCancel}
        onDragEnd={handleDragEnd}
        onDragOver={(event) => {
          const nextTarget = isCalendarDropTarget(event.over?.data.current)
            ? event.over.data.current
            : null

          if (nextTarget) {
            lastDropTargetRef.current = nextTarget
            setActiveDropTarget(nextTarget)
            return
          }

          setActiveDropTarget(lastDropTargetRef.current)
        }}
        onDragStart={handleDragStart}
        sensors={sensors}
      >
        <div
          className={getCalendarSlotClassName(
            classNames,
            "shell",
            "flex min-h-0 flex-1 flex-col bg-background"
          )}
        >
          {resolvedView === "month" ? (
            <CalendarMonthView {...sharedViewProps} />
          ) : null}
          {resolvedView === "week" ? (
            <CalendarWeekView
              {...sharedViewProps}
              maxHour={maxHour}
              minHour={minHour}
            />
          ) : null}
          {resolvedView === "day" ? (
            <CalendarDayView
              {...sharedViewProps}
              maxHour={maxHour}
              minHour={minHour}
            />
          ) : null}
          {resolvedView === "agenda" ? (
            <CalendarAgendaView
              {...sharedViewProps}
              range={getVisibleRange(date, "agenda", {
                agendaDays,
                hiddenDays: resolvedHiddenDays,
                hourCycle,
                locale,
                timeZone,
              })}
            />
          ) : null}
        </div>
        {isHydrated ? createPortal(portals, document.body) : null}
      </DndContext>
      <p
        aria-live="polite"
        className="sr-only"
        data-testid="calendar-live-announcement"
      >
        {liveAnnouncement}
      </p>
    </div>
  )
}

function getPreviewOccurrence(
  activeDrag: CalendarDragData,
  target: CalendarDropTarget,
  slotDuration: number,
  dragOffsetMinutes = 0
) {
  if (activeDrag.kind === "event") {
    const operation = getMoveOperation(
      activeDrag.occurrence,
      target,
      activeDrag.variant === "time-grid" ? dragOffsetMinutes : 0
    )

    return {
      ...activeDrag.occurrence,
      start: operation.nextStart,
      end: operation.nextEnd,
      allDay: operation.allDay ?? activeDrag.occurrence.allDay,
    }
  }

  const operation = getResizeOperation(
    activeDrag.occurrence,
    activeDrag.edge,
    target,
    slotDuration
  )

  return {
    ...activeDrag.occurrence,
    start: operation.nextStart,
    end: operation.nextEnd,
  }
}

function getMoveOperation(
  occurrence: CalendarOccurrence,
  target: CalendarDropTarget,
  dragOffsetMinutes = 0
): CalendarMoveOperation {
  const durationMs = occurrence.end.getTime() - occurrence.start.getTime()
  let nextStart: Date
  let nextEnd: Date
  let allDay = occurrence.allDay

  if (target.kind === "slot") {
    const durationMinutes = Math.max(1, Math.round(durationMs / 60_000))
    const latestStartMinute = Math.max(
      0,
      1_440 - Math.min(durationMinutes, 1_440)
    )
    const nextStartMinute = Math.min(
      latestStartMinute,
      Math.max(0, target.minuteOfDay - dragOffsetMinutes)
    )

    nextStart = setMinuteOfDay(startOfDay(target.day), nextStartMinute)
    nextEnd = new Date(nextStart.getTime() + durationMs)
    allDay = false
  } else {
    allDay = target.kind === "all-day" || occurrence.allDay

    if (allDay) {
      nextStart = startOfDay(target.day)
      nextEnd = addDays(nextStart, getDaySpan(occurrence))
    } else {
      nextStart = copyTimeParts(startOfDay(target.day), occurrence.start)
      nextEnd = new Date(nextStart.getTime() + durationMs)
    }
  }

  return {
    occurrence,
    nextStart,
    nextEnd,
    previousStart: occurrence.start,
    previousEnd: occurrence.end,
    allDay,
  }
}

function getDragOffsetMinutes(
  dragData: CalendarDragData,
  dragRect: ClientRect | null,
  activatorEvent: Event | null
) {
  if (
    dragData.kind !== "event" ||
    dragData.variant !== "time-grid" ||
    dragData.occurrence.allDay ||
    !dragRect ||
    dragRect.height <= 0
  ) {
    return 0
  }

  const clientY = getClientY(activatorEvent)

  if (clientY === null) {
    return 0
  }

  const durationMinutes = Math.max(
    1,
    Math.round(
      (dragData.occurrence.end.getTime() - dragData.occurrence.start.getTime()) /
        60_000
    )
  )
  const pointerOffsetY = Math.min(
    dragRect.height,
    Math.max(0, clientY - dragRect.top)
  )

  return Math.min(
    Math.max(0, durationMinutes - 1),
    Math.round((pointerOffsetY / dragRect.height) * durationMinutes)
  )
}

function getClientY(event: Event | null) {
  if (!event) {
    return null
  }

  if (isPointerLikeEvent(event)) {
    return event.clientY
  }

  if (isTouchEvent(event) && event.touches.length > 0) {
    return event.touches[0]?.clientY ?? null
  }

  if (isTouchEvent(event) && event.changedTouches.length > 0) {
    return event.changedTouches[0]?.clientY ?? null
  }

  return null
}

function isPointerLikeEvent(
  event: Event
): event is Event & {
  clientY: number
} {
  return "clientY" in event && typeof event.clientY === "number"
}

function isTouchEvent(
  event: Event
): event is Event & {
  changedTouches: TouchList
  touches: TouchList
} {
  return "touches" in event && "changedTouches" in event
}

function getResizeOperation(
  occurrence: CalendarOccurrence,
  edge: "start" | "end",
  target: CalendarDropTarget,
  slotDuration: number
): CalendarResizeOperation {
  const rawDate =
    target.kind === "slot"
      ? setMinuteOfDay(startOfDay(target.day), target.minuteOfDay)
      : startOfDay(target.day)

  if (edge === "start") {
    return {
      occurrence,
      edge,
      nextStart: clampResize(rawDate, occurrence.end, "start", slotDuration),
      nextEnd: occurrence.end,
      previousStart: occurrence.start,
      previousEnd: occurrence.end,
    }
  }

  const adjustedEnd =
    target.kind === "slot" ? addMinutes(rawDate, slotDuration) : addDays(rawDate, 1)

  return {
    occurrence,
    edge,
    nextStart: occurrence.start,
    nextEnd: clampResize(adjustedEnd, occurrence.start, "end", slotDuration),
    previousStart: occurrence.start,
    previousEnd: occurrence.end,
  }
}

function isCalendarDropTarget(value: unknown): value is CalendarDropTarget {
  if (!value || typeof value !== "object") {
    return false
  }

  const candidate = value as Partial<CalendarDropTarget>

  if (candidate.kind === "slot") {
    return candidate.day instanceof Date && typeof candidate.minuteOfDay === "number"
  }

  if (candidate.kind === "day" || candidate.kind === "all-day") {
    return candidate.day instanceof Date
  }

  return false
}

function isCalendarDragData(value: unknown): value is CalendarDragData {
  if (!value || typeof value !== "object") {
    return false
  }

  const candidate = value as Partial<CalendarDragData>

  if (candidate.kind !== "event" && candidate.kind !== "resize") {
    return false
  }

  const occurrence = candidate.occurrence

  if (
    !occurrence ||
    typeof occurrence !== "object" ||
    !(occurrence.start instanceof Date) ||
    !(occurrence.end instanceof Date)
  ) {
    return false
  }

  if (candidate.kind === "resize") {
    return candidate.edge === "start" || candidate.edge === "end"
  }

  return true
}

function getTimeGridDropTargetFromPoint(
  clientX: number,
  clientY: number
): CalendarDropTarget | null {
  if (typeof document === "undefined") {
    return null
  }

  const match = document
    .elementsFromPoint(clientX, clientY)
    .find((element): element is HTMLElement => {
      return (
        element instanceof HTMLElement &&
        element.dataset.calendarDropTargetKind === "slot"
      )
    })

  if (!match) {
    return null
  }

  const dayValue = match.dataset.calendarDropTargetDay
  const minuteValue = match.dataset.calendarDropTargetMinute

  if (!dayValue || minuteValue === undefined) {
    return null
  }

  const day = new Date(dayValue)
  const minuteOfDay = Number(minuteValue)

  if (Number.isNaN(day.getTime()) || !Number.isFinite(minuteOfDay)) {
    return null
  }

  return {
    kind: "slot",
    day,
    minuteOfDay,
  }
}

"use client"

import * as React from "react"

import { useDroppable } from "@dnd-kit/core"
import { isSameDay, startOfDay } from "date-fns"

import { cn } from "@/lib/utils"

import type {
  CalendarClassNames,
  CalendarCreateDraft,
  CalendarDropTarget,
  CalendarEventRenderer,
  CalendarOccurrence,
} from "../../types"
import {
  formatHourLabel,
  formatMonthDayLabel,
  formatWeekday,
  getBlockedSegmentsForDay,
  getAllDayEvents,
  getBusinessHourSegmentsForDay,
  getCalendarSlotClassName,
  getDayLayout,
  getEventMetaLabel,
  getNextVisibleDay,
  getOutsideBusinessHourSegmentsForDay,
  getWeekDays,
  isToday,
  parseTimeStringToMinuteOfDay,
  setMinuteOfDay,
} from "../../utils"
import {
  CalendarEventCard,
  getResolvedAccentColor,
} from "./event-card"
import {
  type CalendarEventMenuPosition,
  type SharedViewProps,
  type TimeGridViewProps,
} from "../shared"

export function CalendarWeekView(
  props: SharedViewProps & {
    minHour: number
    maxHour: number
  }
) {
  return (
    <CalendarTimeGridView
      {...props}
      days={getWeekDays(props.anchorDate, props.weekStartsOn, props.hiddenDays)}
    />
  )
}

export function CalendarDayView(
  props: SharedViewProps & {
    minHour: number
    maxHour: number
  }
) {
  return (
    <CalendarTimeGridView
      {...props}
      days={[startOfDay(getNextVisibleDay(props.anchorDate, props.hiddenDays))]}
    />
  )
}

function CalendarTimeGridView(props: TimeGridViewProps) {
  const [draft, setDraft] = React.useState<CalendarCreateDraft | null>(null)
  const [now, setNow] = React.useState(() => new Date())
  const scrollContainerRef = React.useRef<HTMLDivElement | null>(null)
  const minMinute = props.minHour * 60
  const maxMinute = props.maxHour * 60
  const totalMinutes = maxMinute - minMinute
  const slotCount = Math.max(1, totalMinutes / props.slotDuration)
  const gridHeight = slotCount * props.slotHeight
  const commitDraft = React.useEffectEvent(() => {
    if (!draft || !props.onEventCreate) {
      return
    }

    const startMinute = Math.min(draft.startMinute, draft.endMinute)
    const endMinute = Math.max(draft.startMinute, draft.endMinute)
    const start = setMinuteOfDay(startOfDay(draft.day), startMinute)
    const end = setMinuteOfDay(
      startOfDay(draft.day),
      Math.min(endMinute + props.slotDuration, 1_440)
    )

    props.onEventCreate({
      start,
      end,
    })
    setDraft(null)
  })

  React.useEffect(() => {
    if (!draft) {
      return
    }

    function handlePointerUp() {
      commitDraft()
    }

    window.addEventListener("pointerup", handlePointerUp)

    return () => {
      window.removeEventListener("pointerup", handlePointerUp)
    }
  }, [draft])

  React.useEffect(() => {
    const intervalId = window.setInterval(() => {
      setNow(new Date())
    }, 30_000)

    return () => {
      window.clearInterval(intervalId)
    }
  }, [])

  React.useEffect(() => {
    const container = scrollContainerRef.current

    if (!container || !props.scrollToTime) {
      return
    }

    const currentDate = new Date()
    const targetMinute =
      props.scrollToTime === "now"
        ? currentDate.getHours() * 60 + currentDate.getMinutes()
        : parseTimeStringToMinuteOfDay(props.scrollToTime)

    if (targetMinute === null) {
      return
    }

    const clampedMinute = Math.min(maxMinute, Math.max(minMinute, targetMinute))
    const nextScrollTop = Math.max(
      0,
      ((clampedMinute - minMinute) / props.slotDuration) * props.slotHeight -
        props.slotHeight * 2
    )

    container.scrollTop = nextScrollTop
  }, [
    maxMinute,
    minMinute,
    props.scrollToTime,
    props.slotDuration,
    props.slotHeight,
  ])

  return (
    <div className="min-h-0 flex-1 overflow-auto" ref={scrollContainerRef}>
      <div className="min-w-4xl">
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            Time
          </div>
          {props.days.map((day) => (
            <div
              key={`header-${day.toISOString()}`}
              className={getCalendarSlotClassName(
                props.classNames,
                "timeGridHeader",
                cn(
                  "border-r border-border/70 last:border-r-0",
                  props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
                )
              )}
            >
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[11px] tracking-[0.24em] text-muted-foreground uppercase">
                    {formatWeekday(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                  <p className="text-sm font-medium">
                    {formatMonthDayLabel(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                </div>
                {isToday(day) ? (
                  <span className="rounded-full bg-primary/12 px-2 py-1 text-[11px] font-medium text-primary">
                    Today
                  </span>
                ) : null}
              </div>
            </div>
          ))}
        </div>
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            All day
          </div>
          {props.days.map((day) => (
            <AllDayDropZone
              key={`all-day-${day.toISOString()}`}
              classNames={props.classNames}
              day={day}
              density={props.density}
              dragPreviewOccurrence={props.dragPreviewOccurrence}
              events={getAllDayEvents(props.occurrences, day)}
              getEventColor={props.getEventColor}
              hourCycle={props.hourCycle}
              interactive={props.interactive}
              locale={props.locale}
              onEventKeyCommand={props.onEventKeyCommand}
              onOpenContextMenu={props.onOpenContextMenu}
              onSelect={props.onSelectEvent}
              previewOccurrenceId={props.previewOccurrenceId}
              renderEvent={props.renderEvent}
              selectedEventId={props.selectedEventId}
              timeZone={props.timeZone}
            />
          ))}
        </div>
        <div
          className={getCalendarSlotClassName(
            props.classNames,
            "timeGrid",
            "grid"
          )}
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div className="relative border-r border-border/70">
            {Array.from({ length: slotCount }).map((_, index) => {
              const minute = minMinute + index * props.slotDuration
              const labelDate = setMinuteOfDay(
                startOfDay(props.days[0]),
                minute
              )

              return (
                <div
                  key={`time-label-${minute}`}
                  className="border-b border-border/50 px-3 text-[11px] text-muted-foreground"
                  style={{
                    height: props.slotHeight,
                  }}
                >
                  {minute % 60 === 0
                    ? formatHourLabel(labelDate, {
                        hourCycle: props.hourCycle,
                        locale: props.locale,
                        timeZone: props.timeZone,
                      })
                    : null}
                </div>
              )
            })}
          </div>
          {props.days.map((day) => {
            const layout = getDayLayout(
              props.occurrences,
              day,
              minMinute,
              maxMinute
            )
            const previewLayout = getTimeGridPreviewLayout(
              props.occurrences,
              props.dragPreviewOccurrence,
              day,
              minMinute,
              maxMinute
            )
            const currentMinuteOfDay = now.getHours() * 60 + now.getMinutes()
            const showNowIndicator =
              isSameDay(day, now) &&
              currentMinuteOfDay >= minMinute &&
              currentMinuteOfDay <= maxMinute
            const nowIndicatorTop =
              ((currentMinuteOfDay - minMinute) / totalMinutes) * gridHeight

            return (
              <div
                key={`day-column-${day.toISOString()}`}
                className={getCalendarSlotClassName(
                  props.classNames,
                  "timeGridDayColumn",
                  "relative border-r border-border/70 last:border-r-0"
                )}
              >
                <div
                  className="relative"
                  style={{
                    height: gridHeight,
                  }}
                >
                  <TimeGridBackground
                    blockedRanges={props.blockedRanges}
                    businessHours={props.businessHours}
                    day={day}
                    gridHeight={gridHeight}
                    maxMinute={maxMinute}
                    minMinute={minMinute}
                    slotDuration={props.slotDuration}
                    slotHeight={props.slotHeight}
                  />
                  <div
                    className="absolute inset-0 grid"
                    style={{
                      gridTemplateRows: `repeat(${slotCount}, ${props.slotHeight}px)`,
                    }}
                  >
                    {Array.from({ length: slotCount }).map((_, index) => {
                      const minuteOfDay = minMinute + index * props.slotDuration
                      const slotStart = setMinuteOfDay(startOfDay(day), minuteOfDay)
                      const slotEnd = setMinuteOfDay(
                        startOfDay(day),
                        Math.min(minuteOfDay + props.slotDuration, 1_440)
                      )

                      return (
                        <TimeSlotDropZone
                          key={`${day.toISOString()}-${minuteOfDay}`}
                          classNames={props.classNames}
                          day={day}
                          draft={draft}
                          blocked={
                            props.blockedRanges?.some((range) =>
                              slotStart.getTime() < range.end.getTime() &&
                              slotEnd.getTime() > range.start.getTime()
                            ) ?? false
                          }
                          hourCycle={props.hourCycle}
                          locale={props.locale}
                          minuteOfDay={minuteOfDay}
                          onBeginCreate={() => {
                            if (!props.onEventCreate) {
                              return
                            }

                            setDraft({
                              day,
                              startMinute: minuteOfDay,
                              endMinute: minuteOfDay,
                            })
                          }}
                          onExtendCreate={() => {
                            if (!draft || !isSameDay(draft.day, day)) {
                              return
                            }

                            setDraft({
                              ...draft,
                              endMinute: minuteOfDay,
                            })
                          }}
                        />
                      )
                    })}
                  </div>
                  {draft && isSameDay(draft.day, day) ? (
                    <div
                      className="pointer-events-none absolute inset-x-1 rounded-[calc(var(--radius)*0.9)] border border-dashed border-primary/60 bg-primary/10"
                      style={{
                        top:
                          ((Math.min(draft.startMinute, draft.endMinute) -
                            minMinute) /
                            props.slotDuration) *
                          props.slotHeight,
                        height:
                          ((Math.abs(draft.endMinute - draft.startMinute) +
                            props.slotDuration) /
                            props.slotDuration) *
                          props.slotHeight,
                      }}
                    />
                  ) : null}
                  {previewLayout ? (
                    <div
                      className="pointer-events-none absolute z-10 px-1"
                      style={{
                        top:
                          ((previewLayout.top - minMinute) / props.slotDuration) *
                          props.slotHeight,
                        height: Math.max(
                          props.slotHeight - 4,
                          (previewLayout.height / props.slotDuration) *
                            props.slotHeight
                        ),
                        left: `calc(${(previewLayout.column * 100) / previewLayout.columns}% + 0px)`,
                        width: `calc(${100 / previewLayout.columns}% - 0px)`,
                      }}
                    >
                      <div className="h-full rounded-[min(var(--radius-sm),4px)] border border-dashed border-foreground/18 bg-foreground/8 shadow-sm dark:border-white/12 dark:bg-white/8" />
                    </div>
                  ) : null}
                  {showNowIndicator ? (
                    <div
                      className="pointer-events-none absolute inset-x-0 z-20"
                      style={{
                        top: nowIndicatorTop,
                      }}
                    >
                      <div className="relative h-0">
                        <div className="absolute top-1/2 left-0 size-2.5 -translate-x-1/2 -translate-y-1/2 rounded-full bg-primary shadow-[0_0_0_3px_var(--color-background)]" />
                        <div className="h-0.5 w-full bg-primary" />
                      </div>
                    </div>
                  ) : null}
                  {layout.map((item, index) => {
                    const width = 100 / item.columns
                    const left = item.column * width

                    return (
                      <div
                        key={item.occurrence.occurrenceId}
                        className="absolute px-1"
                        style={{
                          top:
                            ((item.top - minMinute) / props.slotDuration) *
                            props.slotHeight,
                          height: Math.max(
                            props.slotHeight - 4,
                            (item.height / props.slotDuration) * props.slotHeight
                          ),
                          left: `calc(${left}% + 0px)`,
                          width: `calc(${width}% - 0px)`,
                        }}
                      >
                        <CalendarEventCard
                          accentColor={getResolvedAccentColor(
                            item.occurrence,
                            props.getEventColor,
                            index
                          )}
                          classNames={props.classNames}
                          density={props.density}
                          dragInstanceId={`time-grid:${day.toISOString()}:${item.occurrence.occurrenceId}`}
                          event={item.occurrence}
                          interactive={props.interactive}
                          onEventKeyCommand={props.onEventKeyCommand}
                          onResizeHandlePointerDown={
                            props.onResizeHandlePointerDown
                          }
                          onOpenContextMenu={props.onOpenContextMenu}
                          onSelect={props.onSelectEvent}
                          preview={
                            props.previewOccurrenceId ===
                            item.occurrence.occurrenceId
                          }
                          renderEvent={props.renderEvent}
                          selected={
                            props.selectedEventId ===
                            item.occurrence.occurrenceId
                          }
                          showResizeHandles
                          timeLabel={getEventMetaLabel(
                            item.occurrence,
                            {
                              hourCycle: props.hourCycle,
                              locale: props.locale,
                              timeZone: props.timeZone,
                            }
                          )}
