          blocked ? "cursor-not-allowed" : "",
          draft && isSameDay(draft.day, day) ? "cursor-crosshair" : ""
        )
      )}
      onPointerDown={(event) => {
        if (event.button !== 0 || blocked) {
          return
        }

        onBeginCreate()
      }}
      onPointerEnter={onExtendCreate}
      type="button"
    />
  )
}

