"use client"

import type {
  CSSProperties,
  KeyboardEvent,
  MouseEvent,
  PointerEvent as ReactPointerEvent,
} from "react"

import {
  useDraggable,
  type DraggableAttributes,
  type DraggableSyntheticListeners,
} from "@dnd-kit/core"
import { CSS } from "@dnd-kit/utilities"

import { cn } from "@/lib/utils"

import type {
  CalendarClassNames,
  CalendarDensity,
  CalendarDragData,
  CalendarEventRenderer,
  CalendarOccurrence,
} from "../../types"
import { getCalendarSlotClassName, getOccurrenceAccentColor } from "../../utils"
import type { CalendarEventMenuPosition, EventVariant } from "../shared"

type CalendarEventCardProps = {
  accentColor: string
  classNames?: CalendarClassNames
  density?: CalendarDensity
  dragInstanceId: string
  event: CalendarOccurrence
  interactive: boolean
  onEventKeyCommand: (
    occurrence: CalendarOccurrence,
    event: KeyboardEvent<HTMLButtonElement>
  ) => void
  onResizeHandlePointerDown?: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: ReactPointerEvent<HTMLSpanElement>
  ) => void
  onOpenContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onSelect: (occurrence: CalendarOccurrence) => void
  preview?: boolean
  renderEvent?: CalendarEventRenderer
  selected?: boolean
  showResizeHandles?: boolean
  timeLabel: string
  variant: EventVariant
}

type EventSurfaceProps = {
  accentColor: string
  ariaLabel?: string
  attributes?: DraggableAttributes
  className?: string
  density?: CalendarDensity
  event: CalendarOccurrence
  isDragging?: boolean
  listeners?: DraggableSyntheticListeners
  nodeRef?: (element: HTMLButtonElement | null) => void
  overlay?: boolean
  onKeyDown?: (event: KeyboardEvent<HTMLButtonElement>) => void
  onResizeHandlePointerDown?: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: ReactPointerEvent<HTMLSpanElement>
  ) => void
  onOpenContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onSelect?: () => void
  preview?: boolean
  renderEvent?: CalendarEventRenderer
  selected?: boolean
  showResizeHandles?: boolean
  style?: CSSProperties
  timeLabel: string
  variant: EventVariant
}

export function CalendarEventCard({
  accentColor,
  classNames,
  density = "comfortable",
  dragInstanceId,
  event,
  interactive,
  onEventKeyCommand,
  onResizeHandlePointerDown,
  onOpenContextMenu,
  onSelect,
  preview = false,
  renderEvent,
  selected,
  showResizeHandles,
  timeLabel,
  variant,
}: CalendarEventCardProps) {
  const disabled = event.readOnly
  const dragEnabled = interactive && !disabled && !preview
  const { attributes, listeners, setNodeRef, transform, isDragging } =
    useDraggable({
      id: `event:${dragInstanceId}`,
      data: {
        kind: "event",
        occurrence: event,
        variant,
      } satisfies CalendarDragData,
      disabled: !dragEnabled,
    })

  return (
    <div
      className={variant === "time-grid" ? "h-full" : undefined}
      style={{
        transform: CSS.Translate.toString(transform),
      }}
    >
      <EventSurface
        accentColor={accentColor}
        ariaLabel={`${event.title}. ${timeLabel}.`}
        attributes={dragEnabled ? attributes : undefined}
        className={getEventSlotClassName(classNames, variant)}
        density={density}
        event={event}
        isDragging={isDragging}
        listeners={dragEnabled ? listeners : undefined}
        nodeRef={dragEnabled ? setNodeRef : undefined}
        onKeyDown={(keyEvent) => onEventKeyCommand(event, keyEvent)}
        onResizeHandlePointerDown={onResizeHandlePointerDown}
        onOpenContextMenu={onOpenContextMenu}
        onSelect={() => onSelect(event)}
        preview={preview}
        renderEvent={renderEvent}
        selected={selected}
        showResizeHandles={showResizeHandles && interactive && !preview}
        timeLabel={timeLabel}
        variant={variant}
      />
    </div>
  )
}

export function EventSurface({
  accentColor,
  ariaLabel,
  attributes,
  className,
  density = "comfortable",
  event,
  isDragging = false,
  listeners,
  nodeRef,
  overlay = false,
  onKeyDown,
  onResizeHandlePointerDown,
  onOpenContextMenu,
  onSelect,
  preview = false,
  renderEvent,
  selected,
  showResizeHandles,
  style,
  timeLabel,
  variant,
}: EventSurfaceProps) {
  const isCompact = variant === "month" || variant === "all-day"
  function openContextMenu(position: CalendarEventMenuPosition) {
    if (!onOpenContextMenu || overlay) {
      return
    }

    onSelect?.()
    onOpenContextMenu(event, position)
  }

  function handleContextMenu(event: MouseEvent<HTMLButtonElement>) {
    event.preventDefault()
    event.stopPropagation()
    openContextMenu({
      x: event.clientX,
      y: event.clientY,
    })
  }

  function handleKeyDown(event: KeyboardEvent<HTMLButtonElement>) {
    onKeyDown?.(event)

    if (event.defaultPrevented || !onOpenContextMenu || overlay) {
      return
    }

    if (
      event.key === "ContextMenu" ||
      (event.shiftKey && event.key === "F10")
    ) {
      const rect = event.currentTarget.getBoundingClientRect()

      event.preventDefault()
      openContextMenu({
        x: rect.left + rect.width / 2,
        y: rect.top + Math.min(rect.height, 24),
      })
    }
  }

  const content = renderEvent ? (
    renderEvent({
      occurrence: event,
      accentColor,
      timeLabel,
      isCompact,
      isDragging,
    })
  ) : (
    <div
      className={cn(
        "min-w-0 space-y-0.5",
        variant === "time-grid" ? "relative z-10" : undefined
      )}
    >
      {!isCompact ? (
        <p className="truncate text-[10px] font-medium tracking-[0.18em] text-muted-foreground uppercase">
          {timeLabel}
        </p>
      ) : null}
      <p className="truncate leading-tight font-medium text-card-foreground">
        {event.title}
      </p>
      {!isCompact && event.location ? (
        <p className="truncate text-[11px] text-muted-foreground">
          {event.location}
        </p>
      ) : null}
      {variant === "agenda" && event.calendarLabel ? (
        <p className="truncate text-[11px] text-muted-foreground">
          {event.calendarLabel}
        </p>
      ) : null}
    </div>
  )

  return (
    <div
      className={cn(
        "group/event relative w-full min-w-0",
        variant === "time-grid" ? "h-full" : undefined
      )}
      data-calendar-drag-surface="true"
      data-selected={selected ? "true" : undefined}
      style={style}
    >
      <button
        aria-label={ariaLabel}
        className={cn(
          getEventSurfaceClassName(
            density,
            variant,
            selected,
            isDragging,
            overlay,
            preview
          ),
          className
        )}
        ref={nodeRef}
        data-calendar-event-id={event.sourceEventId}
        data-calendar-occurrence-id={event.occurrenceId}
        data-calendar-variant={variant}
        data-selected={selected ? "true" : undefined}
        data-testid={`calendar-event-${event.sourceEventId}-${variant}`}
        onClick={onSelect}
        onContextMenu={handleContextMenu}
        onKeyDown={handleKeyDown}
        style={getEventSurfaceStyle()}
        type="button"
        {...attributes}
        {...listeners}
      >
        {preview ? (
          <span
            aria-hidden
            className="pointer-events-none absolute inset-0 rounded-[inherit] border border-dashed opacity-60"
            style={{ borderColor: accentColor }}
          />
        ) : null}
        <span
          aria-hidden
          className="pointer-events-none absolute top-1.5 bottom-1.5 left-1 w-0.5 rounded-full"
          style={{ backgroundColor: accentColor }}
        />
        {content}
      </button>
      {showResizeHandles && !overlay ? (
        <>
          <ResizeHandle
            accentColor={accentColor}
            edge="start"
            event={event}
            interactive
            onPointerDown={onResizeHandlePointerDown}
          />
          <ResizeHandle
            accentColor={accentColor}
            edge="end"
            event={event}
            interactive
            onPointerDown={onResizeHandlePointerDown}
          />
        </>
      ) : null}
    </div>
  )
}

export function getResolvedAccentColor(
  occurrence: CalendarOccurrence,
  getEventColor?: (occurrence: CalendarOccurrence) => string,
  index = 0
) {
  return (
    getEventColor?.(occurrence) ?? getOccurrenceAccentColor(occurrence, index)
  )
}

function ResizeHandle({
  accentColor,
  edge,
  event,
  interactive,
  onPointerDown,
}: {
  accentColor: string
  edge: "start" | "end"
  event: CalendarOccurrence
  interactive: boolean
  onPointerDown?: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: ReactPointerEvent<HTMLSpanElement>
  ) => void
}) {
  return (
    <span
      data-calendar-event-id={event.sourceEventId}
      data-calendar-occurrence-id={event.occurrenceId}
      data-calendar-resize-handle={edge}
      data-testid={`calendar-resize-handle-${event.sourceEventId}-${edge}`}
      className={cn(
        "absolute inset-x-0 z-20 h-6 touch-none select-none",
        edge === "start"
          ? "top-0 cursor-ns-resize"
          : "bottom-0 cursor-ns-resize"
      )}
      onPointerDown={(pointerEvent) => {
        if (!interactive || pointerEvent.button !== 0) {
          return
        }

        pointerEvent.preventDefault()
        pointerEvent.stopPropagation()
        onPointerDown?.(event, edge, pointerEvent)
      }}
      style={{
        transform: edge === "start" ? "translateY(-50%)" : "translateY(50%)",
      }}
    >
      <span
        aria-hidden
        className={cn(
          "pointer-events-none absolute inset-x-1.5 top-1/2 h-px -translate-y-1/2 opacity-0 transition-opacity duration-150 group-hover/event:opacity-100 group-focus-visible/event:opacity-100",
          selectedHandleVisibilityClass(false)
        )}
        style={{
          backgroundColor: `${accentColor}55`,
        }}
      />
      <span
        aria-hidden
        className={cn(
          "pointer-events-none absolute top-1/2 left-1/2 h-1.5 w-8 -translate-x-1/2 -translate-y-1/2 rounded-full border border-background/90 opacity-0 shadow-sm transition-[opacity,transform] duration-150 group-hover/event:scale-100 group-hover/event:opacity-100 group-focus-visible/event:scale-100 group-focus-visible/event:opacity-100",
          selectedHandleVisibilityClass(false),
          "scale-95"
        )}
        style={{
          backgroundColor: `${accentColor}88`,
        }}
      />
    </span>
  )
}

function getEventSlotClassName(
  classNames: CalendarClassNames | undefined,
  variant: EventVariant
) {
  const slot =
    variant === "month"
      ? "monthEvent"
      : variant === "agenda"
        ? "agendaEvent"
        : "timeGridEvent"

  return getCalendarSlotClassName(classNames, slot)
}

function getEventSurfaceStyle(): CSSProperties {
  return {
    borderColor: "var(--color-border)",
    backgroundColor: "var(--color-card)",
    color: "var(--color-card-foreground)",
  }
}

function getEventSurfaceClassName(
  density: CalendarDensity,
  variant: EventVariant,
  selected: boolean | undefined,
  isDragging: boolean,
  overlay: boolean,
  preview: boolean
) {
  return cn(
    "relative w-full min-w-0 overflow-hidden rounded-[min(var(--radius-sm),4px)] border pr-[10px] pl-3 text-left shadow-xs transition-[border-color,box-shadow,opacity] duration-150 outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/40",
    density === "compact" ? "px-2 py-1.5" : "px-2 py-2",
    variant === "month" || variant === "all-day"
      ? density === "compact"
        ? "px-2 py-1 pl-3 text-[11px]"
        : "px-2 py-1.5 pl-3 text-xs"
      : "text-sm",
    variant === "agenda" ? "min-h-20" : "",
    variant === "time-grid" ? "h-full" : "",
    selected ? "border-ring ring-2 ring-ring/60" : "",
    preview ? "shadow-sm" : "",
    overlay
      ? "pointer-events-none shadow-sm"
      : isDragging && !preview
        ? "opacity-0"
        : "hover:border-foreground/15"
  )
}

function selectedHandleVisibilityClass(isDragging: boolean) {
  return isDragging
    ? "opacity-100"
    : "group-data-[selected=true]/event:opacity-100"
}

"use client"

import * as React from "react"
import type { ElementType } from "react"

import {
  ArchiveBoxIcon,
  ClockIcon,
  CopySimpleIcon,
  MapPinIcon,
  TrashIcon,
} from "@phosphor-icons/react"

import { cn } from "@/lib/utils"

import type { CalendarOccurrence } from "../../types"
import { getEventMetaLabel, getOccurrenceAccentColor } from "../../utils"

type CalendarEventContextMenuProps = {
  hourCycle?: 12 | 24
  locale?: string
  occurrence: CalendarOccurrence
  onArchive?: () => void
  onClose: () => void
  onDelete?: () => void
  onDuplicate?: () => void
  timeZone?: string
  x: number
  y: number
}

const FALLBACK_MENU_WIDTH = 220
const VIEWPORT_MARGIN = 16

export function CalendarEventContextMenu({
  hourCycle,
  locale,
  occurrence,
  onArchive,
  onClose,
  onDelete,
  onDuplicate,
  timeZone,
  x,
  y,
}: CalendarEventContextMenuProps) {
  const menuRef = React.useRef<HTMLDivElement>(null)
  const itemRefs = React.useRef<Array<HTMLButtonElement | null>>([])
  const [position, setPosition] = React.useState({ x, y })
  const accentColor = getOccurrenceAccentColor(occurrence)
  const actions = React.useMemo(
    () =>
      [
        onDuplicate
          ? {
              icon: CopySimpleIcon,
              key: "duplicate",
              label: "Duplicate event",
              onSelect: onDuplicate,
            }
          : null,
        onArchive
          ? {
              icon: ArchiveBoxIcon,
              key: "archive",
              label: "Archive event",
              onSelect: onArchive,
            }
          : null,
        onDelete
          ? {
              destructive: true,
              icon: TrashIcon,
              key: "delete",
              label: "Delete event",
              onSelect: onDelete,
            }
          : null,
      ].filter((action) => action !== null),
    [onArchive, onDelete, onDuplicate]
  )

  React.useLayoutEffect(() => {
    const menuElement = menuRef.current

    if (!menuElement) {
      return
    }

    const rect = menuElement.getBoundingClientRect()

    setPosition({
      x: Math.min(
        Math.max(x, VIEWPORT_MARGIN),
        window.innerWidth -
          Math.max(rect.width, FALLBACK_MENU_WIDTH) -
          VIEWPORT_MARGIN
      ),
      y: Math.min(
        Math.max(y, VIEWPORT_MARGIN),
        window.innerHeight - rect.height - VIEWPORT_MARGIN
      ),
    })
  }, [x, y])

  React.useEffect(() => {
    function handlePointerDown(event: PointerEvent) {
      if (
        menuRef.current &&
        event.target instanceof Node &&
        !menuRef.current.contains(event.target)
      ) {
        onClose()
      }
    }

    function handleKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        onClose()
      }
    }

    function handleViewportChange() {
      onClose()
    }

    window.addEventListener("pointerdown", handlePointerDown)
    window.addEventListener("keydown", handleKeyDown)
    window.addEventListener("resize", handleViewportChange)
    window.addEventListener("scroll", handleViewportChange, true)

    return () => {
      window.removeEventListener("pointerdown", handlePointerDown)
      window.removeEventListener("keydown", handleKeyDown)
      window.removeEventListener("resize", handleViewportChange)
      window.removeEventListener("scroll", handleViewportChange, true)
    }
  }, [onClose])

  React.useEffect(() => {
    itemRefs.current[0]?.focus()
  }, [actions.length])

  function handleMenuKeyDown(event: React.KeyboardEvent<HTMLDivElement>) {
    if (event.key === "ArrowDown" || event.key === "ArrowUp") {
      event.preventDefault()

      const currentIndex = itemRefs.current.findIndex(
        (item) => item === document.activeElement
      )
      const direction = event.key === "ArrowDown" ? 1 : -1
      const nextIndex =
        currentIndex === -1
          ? 0
          : (currentIndex + direction + actions.length) % actions.length

      itemRefs.current[nextIndex]?.focus()
      return
    }

    if (event.key === "Home") {
      event.preventDefault()
      itemRefs.current[0]?.focus()
      return
    }

    if (event.key === "End") {
      event.preventDefault()
      itemRefs.current[actions.length - 1]?.focus()
    }
  }

  return (
    <div
      ref={menuRef}
      aria-label={`Actions for ${occurrence.title}`}
      className="fixed z-50 w-[15rem] overflow-hidden rounded-[calc(var(--radius)*1.05)] border border-border/80 bg-popover/98 p-1 shadow-[0_18px_48px_-24px_rgba(15,23,42,0.52)] ring-1 ring-black/5 backdrop-blur-xl animate-in fade-in-0 zoom-in-95"
      data-testid="calendar-event-context-menu"
      onKeyDown={handleMenuKeyDown}
      role="menu"
      style={{
        left: position.x,
        top: position.y,
      }}
    >
      <div className="border-b border-border/70 px-2.5 py-2">
        <div className="flex items-center gap-2.5">
          <span className="inline-flex size-6 shrink-0 items-center justify-center rounded-md bg-muted/55">
            <span
              aria-hidden
              className="size-2 rounded-full"
              style={{ backgroundColor: accentColor }}
            />
          </span>
          <div className="min-w-0 flex-1">
            <p className="truncate text-[13px] font-medium text-popover-foreground">
              {occurrence.title}
            </p>
            <div className="mt-0.5 flex flex-wrap items-center gap-x-2 gap-y-0.5 text-[11px] text-muted-foreground">
              <span className="inline-flex items-center gap-1">
                <ClockIcon className="size-3" />
                {getEventMetaLabel(occurrence, {
                  hourCycle,
                  locale,
                  timeZone,
                })}
              </span>
              <span className="truncate text-[10px] tracking-[0.18em] uppercase">
                {occurrence.calendarLabel ??
                  occurrence.resourceId ??
                  "Event"}
              </span>
            </div>
            {occurrence.location ? (
              <p className="mt-0.5 truncate text-[11px] text-muted-foreground">
                <span className="inline-flex items-center gap-1">
                  <MapPinIcon className="size-3" />
                  {occurrence.location}
                </span>
              </p>
            ) : null}
          </div>
        </div>
      </div>
      <div className="py-1">
        {actions.map((action, index) => (
          <ContextActionButton
            key={action.key}
            buttonRef={(element) => {
              itemRefs.current[index] = element
            }}
            destructive={action.destructive}
            icon={action.icon}
            label={action.label}
            onClick={action.onSelect}
            testId={`calendar-event-action-${action.key}`}
          />
        ))}
      </div>
    </div>
  )
}

function ContextActionButton({
  buttonRef,
  destructive = false,
  icon: Icon,
  label,
  onClick,
  testId,
}: {
  buttonRef?: (element: HTMLButtonElement | null) => void
  destructive?: boolean
  icon: ElementType<{ className?: string }>
  label: string
  onClick: () => void
  testId: string
}) {
  return (
    <button
      className={cn(
        "group mx-1 flex w-[calc(100%-0.5rem)] items-center gap-2.5 rounded-[calc(var(--radius)*0.75)] px-2 py-1.5 text-left transition-colors outline-none focus-visible:ring-2 focus-visible:ring-ring/70",
        destructive
          ? "text-destructive hover:bg-destructive/10"
          : "text-popover-foreground hover:bg-accent/70 hover:text-accent-foreground"
      )}
      data-testid={testId}
      onClick={onClick}
      ref={buttonRef}
      role="menuitem"
      type="button"
    >
      <span
        className={cn(
          "inline-flex size-6 shrink-0 items-center justify-center rounded-md transition-colors",
          destructive
            ? "bg-destructive/10 text-destructive"
            : "bg-muted/55 text-muted-foreground group-hover:bg-accent group-hover:text-accent-foreground"
        )}
      >
        <Icon className="size-3.5" />
      </span>
      <span className="min-w-0 truncate text-[13px] font-medium">
        {label}
      </span>
    </button>
  )
}

"use client"

import * as React from "react"

import { ArrowsOutCardinalIcon, ClockClockwiseIcon } from "@phosphor-icons/react"

import { Button } from "@/components/ui/button"

import type {
  CalendarEventChangeConfirmation,
  CalendarEventChangeConfirmationContext,
} from "../../types"

type CalendarEventChangeConfirmationDialogProps = {
  config?: CalendarEventChangeConfirmation
  context: CalendarEventChangeConfirmationContext | null
  hourCycle?: 12 | 24
  locale?: string
  onCancel: () => void
  onConfirm: () => void
  timeZone?: string
}

export function CalendarEventChangeConfirmationDialog({
  config,
  context,
  hourCycle,
  locale,
  onCancel,
  onConfirm,
  timeZone,
}: CalendarEventChangeConfirmationDialogProps) {
  React.useEffect(() => {
    if (!context) {
      return
    }

    function handleKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        onCancel()
      }
    }

    window.addEventListener("keydown", handleKeyDown)

    return () => {
      window.removeEventListener("keydown", handleKeyDown)
    }
  }, [context, onCancel])

  if (!context) {
    return null
  }

  const resolvedTitle = resolveConfiguredText(
    config,
    "title",
    context,
    getDefaultTitle(context)
  )
  const resolvedDescription = resolveConfiguredText(
    config,
    "description",
    context,
    getDefaultDescription(context, {
      hourCycle,
      locale,
      timeZone,
    })
  )
  const resolvedConfirmLabel = resolveConfiguredText(
    config,
    "confirmLabel",
    context,
    context.action === "move" ? "Apply change" : "Apply resize"
  )
  const resolvedCancelLabel =
    typeof config === "object" ? config.cancelLabel ?? "Cancel" : "Cancel"
  const Icon =
    context.action === "move" ? ArrowsOutCardinalIcon : ClockClockwiseIcon

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/45 px-4 py-6 backdrop-blur-sm">
      <button
        aria-label="Close confirmation dialog"
        className="absolute inset-0"
        onClick={onCancel}
        type="button"
      />
      <div
        aria-modal="true"
        className="relative z-10 w-full max-w-md rounded-[calc(var(--radius)*1.2)] border border-border/80 bg-background p-5 shadow-[0_32px_90px_-40px_rgba(15,23,42,0.65)]"
        data-testid="calendar-event-change-confirmation-dialog"
        role="dialog"
      >
        <div className="flex items-start gap-3">
          <div className="inline-flex size-10 shrink-0 items-center justify-center rounded-[calc(var(--radius)*0.85)] bg-primary/10 text-primary">
            <Icon className="size-5" />
          </div>
          <div className="min-w-0 flex-1">
            <h2 className="text-base font-semibold tracking-tight">
              {resolvedTitle}
            </h2>
            <p className="mt-1 text-sm leading-6 text-muted-foreground">
              {resolvedDescription}
            </p>
          </div>
        </div>
        <div className="mt-4 rounded-[calc(var(--radius)*0.95)] border border-border/70 bg-muted/30 px-3 py-3 text-sm">
          <p className="font-medium text-foreground">{context.occurrence.title}</p>
          <div className="mt-2 grid gap-2 text-muted-foreground sm:grid-cols-2">
            <div>
              <p className="text-[11px] tracking-[0.2em] uppercase">From</p>
              <p className="mt-1 text-sm text-foreground">
                {formatEventRange(
                  context.previousStart,
                  context.previousEnd,
                  {
                    hourCycle,
                    locale,
                    timeZone,
                  },
                  context.occurrence.allDay
                )}
              </p>
            </div>
            <div>
              <p className="text-[11px] tracking-[0.2em] uppercase">To</p>
              <p className="mt-1 text-sm text-foreground">
                {formatEventRange(
                  context.nextStart,
                  context.nextEnd,
                  {
                    hourCycle,
                    locale,
                    timeZone,
                  },
                  context.action === "move"
                    ? context.allDay ?? context.occurrence.allDay
                    : context.occurrence.allDay
                )}
              </p>
            </div>
          </div>
        </div>
        <div className="mt-5 flex justify-end gap-2">
          <Button
            data-testid="calendar-event-change-cancel"
            onClick={onCancel}
            variant="outline"
          >
            {resolvedCancelLabel}
          </Button>
          <Button
            autoFocus
            data-testid="calendar-event-change-confirm"
            onClick={onConfirm}
          >
            {resolvedConfirmLabel}
          </Button>
        </div>
      </div>
    </div>
  )
}

function getDefaultTitle(context: CalendarEventChangeConfirmationContext) {
  return context.action === "move"
    ? "Confirm appointment change"
    : "Confirm appointment resize"
}

function getDefaultDescription(
  context: CalendarEventChangeConfirmationContext,
  options: {
    hourCycle?: 12 | 24
    locale?: string
    timeZone?: string
  } = {}
) {
  const actionLabel =
    context.action === "move"
      ? "apply the new time and date"
      : "apply the new duration"

  return `Review the updated schedule for "${context.occurrence.title}" before you ${actionLabel}. ${formatEventRange(context.nextStart, context.nextEnd, options, context.action === "move" ? context.allDay ?? context.occurrence.allDay : context.occurrence.allDay)}`
}

function formatEventRange(
  start: Date,
  end: Date,
  options: {
    hourCycle?: 12 | 24
    locale?: string
    timeZone?: string
  },
  allDay: boolean | undefined
) {
  if (allDay) {
    const inclusiveEnd = new Date(end.getTime() - 60_000)
    const dateFormatter = new Intl.DateTimeFormat(options.locale, {
      day: "numeric",
      month: "short",
      ...(options.timeZone ? { timeZone: options.timeZone } : {}),
      weekday: "short",
    })

    return `${dateFormatter.format(start)} - ${dateFormatter.format(inclusiveEnd)}`
  }

  const formatter = new Intl.DateTimeFormat(options.locale, {
    day: "numeric",
    hour: options.hourCycle === 24 ? "2-digit" : "numeric",
    minute: "2-digit",
    month: "short",
    ...(options.timeZone ? { timeZone: options.timeZone } : {}),
    ...(options.hourCycle ? { hour12: options.hourCycle === 12 } : {}),
    weekday: "short",
  })
  const timeFormatter = new Intl.DateTimeFormat(options.locale, {
    hour: options.hourCycle === 24 ? "2-digit" : "numeric",
    minute: "2-digit",
    ...(options.timeZone ? { timeZone: options.timeZone } : {}),
    ...(options.hourCycle ? { hour12: options.hourCycle === 12 } : {}),
  })

  return `${formatter.format(start)} - ${timeFormatter.format(end)}`
}

function resolveConfiguredText(
  config: CalendarEventChangeConfirmation | undefined,
  key: "confirmLabel" | "description" | "title",
  context: CalendarEventChangeConfirmationContext,
  fallback: string
) {
  if (typeof config !== "object" || !config[key]) {
    return fallback
  }

  const value = config[key]

  return typeof value === "function" ? value(context) : value
}

"use client"

import * as React from "react"

import { CalendarBlankIcon, ClockIcon, NotePencilIcon } from "@phosphor-icons/react"
import { addDays, format } from "date-fns"

import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"

import type {
  CalendarCreateOperation,
  CalendarCreateSheetConfig,
  CalendarResource,
} from "../../types"

type CalendarEventCreateSheetProps = {
  config?: CalendarCreateSheetConfig
  initialOperation: CalendarCreateOperation | null
  onOpenChange: (open: boolean) => void
  onSubmit: (operation: CalendarCreateOperation) => string | void
  resources?: CalendarResource[]
  timeZone?: string
}

type CreateFormState = {
  allDay: boolean
  description: string
  endDate: string
  endTime: string
  location: string
  resourceId: string
  startDate: string
  startTime: string
  title: string
}

export function CalendarEventCreateSheet({
  config,
  initialOperation,
  onOpenChange,
  onSubmit,
  resources,
  timeZone,
}: CalendarEventCreateSheetProps) {
  const [formState, setFormState] = React.useState<CreateFormState | null>(null)
  const [error, setError] = React.useState<string>()

  React.useEffect(() => {
    if (!initialOperation) {
      setFormState(null)
      setError(undefined)
      return
    }

    const derivedAllDay = initialOperation.allDay ?? false
    const effectiveEndDate = derivedAllDay
      ? addDays(initialOperation.end, -1)
      : initialOperation.end

    setFormState({
      allDay: derivedAllDay,
      description: initialOperation.description ?? "",
      endDate: format(effectiveEndDate, "yyyy-MM-dd"),
      endTime: format(initialOperation.end, "HH:mm"),
      location: initialOperation.location ?? "",
      resourceId:
        initialOperation.resourceId ?? resources?.[0]?.id ?? "",
      startDate: format(initialOperation.start, "yyyy-MM-dd"),
      startTime: format(initialOperation.start, "HH:mm"),
      title: initialOperation.title ?? "",
    })
    setError(undefined)
  }, [initialOperation, resources])

  React.useEffect(() => {
    if (!initialOperation) {
      return
    }

    function handleKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        onOpenChange(false)
      }
    }

    window.addEventListener("keydown", handleKeyDown)

    return () => {
      window.removeEventListener("keydown", handleKeyDown)
    }
  }, [initialOperation, onOpenChange])

  if (!initialOperation || !formState) {
    return null
  }

  const resolvedTitle =
    typeof config === "object"
      ? config.title ?? "Create appointment"
      : "Create appointment"
  const resolvedDescription =
    typeof config === "object"
      ? config.description ??
        "Add details before the appointment is inserted into the calendar."
      : "Add details before the appointment is inserted into the calendar."
  const resolvedSubmitLabel =
    typeof config === "object" ? config.submitLabel ?? "Save appointment" : "Save appointment"
  const resolvedCancelLabel =
    typeof config === "object" ? config.cancelLabel ?? "Cancel" : "Cancel"

  function updateFormState<Key extends keyof CreateFormState>(
    key: Key,
    value: CreateFormState[Key]
  ) {
    setFormState((currentState) =>
      currentState
        ? {
            ...currentState,
            [key]: value,
          }
        : currentState
    )
  }

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault()

    if (!formState || !initialOperation) {
      return
    }

    const baseOperation = initialOperation

    const trimmedTitle = formState.title.trim()

    if (!trimmedTitle) {
      setError("Title is required.")
      return
    }

    const start = buildDateTime(formState.startDate, formState.startTime)
    const end = formState.allDay
      ? addDays(buildDateTime(formState.endDate, "00:00"), 1)
      : buildDateTime(formState.endDate, formState.endTime)

    if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
      setError("Pick a valid start and end.")
      return
    }

    if (end.getTime() <= start.getTime()) {
      setError("End must be after the start.")
      return
    }

    const selectedResource = resources?.find(
      (resource) => resource.id === formState.resourceId
    )

    const submissionError = onSubmit({
      allDay: formState.allDay,
      calendarId:
        selectedResource?.id ?? baseOperation.calendarId,
      calendarLabel:
        selectedResource?.label ?? baseOperation.calendarLabel,
      color: selectedResource?.color ?? baseOperation.color,
      description: normalizeOptionalText(formState.description),
      end,
      location: normalizeOptionalText(formState.location),
      resourceId:
        selectedResource?.id ??
        normalizeOptionalText(formState.resourceId) ??
        baseOperation.resourceId,
      start,
      timeZone: timeZone ?? baseOperation.timeZone,
      title: trimmedTitle,
    })

    if (submissionError) {
      setError(submissionError)
      return
    }

    onOpenChange(false)
  }

  return (
    <div
      className="fixed inset-0 z-50 flex justify-end bg-black/35 backdrop-blur-[2px]"
      data-testid="calendar-create-sheet"
    >
      <button
        aria-label="Close create appointment sheet"
        className="absolute inset-0"
        onClick={() => onOpenChange(false)}
        type="button"
      />
      <aside className="relative z-10 flex h-full w-full max-w-xl flex-col border-l border-border/80 bg-background shadow-[-24px_0_80px_-40px_rgba(15,23,42,0.65)] animate-in slide-in-from-right">
        <div className="border-b border-border/70 px-6 py-5">
          <div className="flex items-start gap-3">
            <div className="inline-flex size-10 shrink-0 items-center justify-center rounded-[calc(var(--radius)*0.9)] bg-primary/10 text-primary">
              <CalendarBlankIcon className="size-5" />
            </div>
            <div className="min-w-0 flex-1">
              <h2 className="text-lg font-semibold tracking-tight">
                {resolvedTitle}
              </h2>
              <p className="mt-1 text-sm leading-6 text-muted-foreground">
                {resolvedDescription}
              </p>
            </div>
          </div>
        </div>
        <form className="flex min-h-0 flex-1 flex-col" onSubmit={handleSubmit}>
          <div className="min-h-0 flex-1 space-y-6 overflow-y-auto px-6 py-5">
            <section className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="calendar-create-title">Title</Label>
                <Input
                  autoFocus
                  id="calendar-create-title"
                  onChange={(event) => updateFormState("title", event.target.value)}
                  placeholder="Weekly product sync"
                  value={formState.title}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="calendar-create-resource">Calendar</Label>
                <select
                  className={selectClassName}
                  id="calendar-create-resource"
                  onChange={(event) =>
                    updateFormState("resourceId", event.target.value)
                  }
                  value={formState.resourceId}
                >
                  {resources?.length ? (
                    resources.map((resource) => (
                      <option key={resource.id} value={resource.id}>
                        {resource.label}
                      </option>
                    ))
                  ) : (
                    <option value="">Default calendar</option>
                  )}
                </select>
              </div>
            </section>

            <section className="space-y-4">
              <div className="flex items-center justify-between rounded-[calc(var(--radius)*0.95)] border border-border/70 bg-muted/25 px-3 py-2.5">
                <div>
                  <p className="text-sm font-medium">All-day appointment</p>
                  <p className="text-xs text-muted-foreground">
                    Turn off the time fields and span whole days.
                  </p>
                </div>
                <input
                  checked={formState.allDay}
                  className="size-4 rounded border-input bg-background text-primary focus-visible:ring-2 focus-visible:ring-ring/60"
                  onChange={(event) =>
                    updateFormState("allDay", event.target.checked)
                  }
                  type="checkbox"
                />
              </div>
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="calendar-create-start-date">Start date</Label>
                  <Input
                    id="calendar-create-start-date"
                    onChange={(event) =>
                      updateFormState("startDate", event.target.value)
                    }
                    type="date"
                    value={formState.startDate}
                  />
                </div>
                {!formState.allDay ? (
                  <div className="space-y-2">
                    <Label htmlFor="calendar-create-start-time">Start time</Label>
                    <Input
                      id="calendar-create-start-time"
                      onChange={(event) =>
                        updateFormState("startTime", event.target.value)
                      }
                      type="time"
                      value={formState.startTime}
                    />
                  </div>
                ) : null}
                <div className="space-y-2">
                  <Label htmlFor="calendar-create-end-date">
                    {formState.allDay ? "End date" : "End date"}
                  </Label>
                  <Input
                    id="calendar-create-end-date"
                    onChange={(event) =>
                      updateFormState("endDate", event.target.value)
                    }
                    type="date"
                    value={formState.endDate}
                  />
                </div>
                {!formState.allDay ? (
                  <div className="space-y-2">
                    <Label htmlFor="calendar-create-end-time">End time</Label>
                    <Input
                      id="calendar-create-end-time"
                      onChange={(event) =>
                        updateFormState("endTime", event.target.value)
                      }
                      type="time"
                      value={formState.endTime}
                    />
                  </div>
                ) : null}
              </div>
              <div className="rounded-[calc(var(--radius)*0.95)] border border-border/70 bg-muted/25 px-3 py-2.5 text-xs text-muted-foreground">
                <span className="inline-flex items-center gap-1.5">
                  <ClockIcon className="size-3.5" />
                  {timeZone ? `${timeZone} timezone` : "Local timezone"}
                </span>
              </div>
            </section>

            <section className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="calendar-create-location">Location</Label>
                <Input
                  id="calendar-create-location"
                  onChange={(event) =>
                    updateFormState("location", event.target.value)
                  }
                  placeholder="Conference room A"
                  value={formState.location}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="calendar-create-description">Description</Label>
                <div className="relative">
                  <NotePencilIcon className="pointer-events-none absolute top-3 left-3 size-4 text-muted-foreground" />
                  <Textarea
                    className="pl-9"
                    id="calendar-create-description"
                    onChange={(event) =>
                      updateFormState("description", event.target.value)
                    }
                    placeholder="Agenda, notes, attendees, or follow-up context."
                    rows={5}
                    value={formState.description}
                  />
                </div>
              </div>
            </section>
          </div>
          <div className="border-t border-border/70 px-6 py-4">
            {error ? (
              <p className="mb-3 text-sm text-destructive">{error}</p>
            ) : null}
            <div className="flex justify-end gap-2">
              <Button
                data-testid="calendar-create-sheet-cancel"
                onClick={() => onOpenChange(false)}
                type="button"
                variant="outline"
              >
                {resolvedCancelLabel}
              </Button>
              <Button data-testid="calendar-create-sheet-submit" type="submit">
                {resolvedSubmitLabel}
              </Button>
            </div>
          </div>
        </form>
      </aside>
    </div>
  )
}

const selectClassName = cn(
  "flex h-9 w-full min-w-0 rounded-md border border-input bg-background px-3 py-1 text-sm shadow-xs transition-[border-color,box-shadow] outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/40 disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50"
)

function buildDateTime(dateValue: string, timeValue: string) {
  const [year, month, day] = dateValue.split("-").map(Number)
  const [hours, minutes] = timeValue.split(":").map(Number)

  return new Date(year, month - 1, day, hours, minutes, 0, 0)
}

function normalizeOptionalText(value: string) {
  const trimmedValue = value.trim()

  return trimmedValue.length > 0 ? trimmedValue : undefined
}
